import {
  FileSystemAdapter,
  FrontmatterParser,
  OKFFileRepository,
  buildKnowledgeIR,
  loadAkcpConfig,
} from "@akcp/core";
import type { ConformanceReport, ConformanceDetail } from "./types.js";
import path from "path";

export class ConformanceRunner {
  private bundlePath: string;
  private profile: string;

  constructor(bundlePath: string, profile: string = "career") {
    this.bundlePath = bundlePath;
    this.profile = profile;
  }

  public async run(): Promise<ConformanceReport> {
    const report: ConformanceReport = {
      conformanceLevel: "none",
      profileDetected: this.profile,
      passed: 0,
      failed: 0,
      warnings: 0,
      details: [],
    };

    const fsAdapter = new FileSystemAdapter();
    const parser = new FrontmatterParser();

    // Level 1: OKF-compatible (Base Spec)
    let okfCompatible = true;
    try {
      const files = await fsAdapter.listFiles(this.bundlePath, ".md");
      for (const file of files) {
        if (
          file === "index.md" ||
          file === "log.md" ||
          file === "README.md" ||
          file === "WALKTHROUGH.md" ||
          file === "walkthrough.md" ||
          file === "FLAGSHIP_AUDIT.md" ||
          file === "scorecard.md" ||
          file.includes(path.sep + "dist" + path.sep) ||
          file.startsWith("dist" + path.sep) ||
          file.includes(path.sep + "scenarios" + path.sep) ||
          file.startsWith("scenarios" + path.sep) ||
          file.includes(path.sep + "policies" + path.sep) ||
          file.startsWith("policies" + path.sep)
        ) {
          continue;
        }
        const content = await fsAdapter.readFile(
          path.join(this.bundlePath, file),
        );
        try {
          const parsed = parser.parse(
            content,
            path.join(this.bundlePath, file),
            this.bundlePath,
          );
          if (
            !parsed.frontmatter ||
            typeof parsed.frontmatter.type !== "string"
          ) {
            report.failed++;
            okfCompatible = false;
            report.details.push({
              file,
              type: "error",
              message: 'Missing or invalid "type" field in OKF frontmatter',
              ruleId: "OKF-V0.1-4.1",
            });
          } else {
            report.passed++;
          }
        } catch (e: any) {
          report.failed++;
          okfCompatible = false;
          report.details.push({
            file,
            type: "error",
            message: `OKF Parse Error: ${e.message}`,
            ruleId: "OKF-V0.1-3.2",
          });
        }
      }
    } catch (e: any) {
      okfCompatible = false;
    }

    if (!okfCompatible) {
      report.conformanceLevel = "none";
      return report;
    }
    report.conformanceLevel = "OKF-compatible";

    // Level 2: AKCP-profile-compatible
    let akcpCompatible = true;
    try {
      const repo = new OKFFileRepository(fsAdapter, parser, this.bundlePath);
      const docs = await repo.findAll();
      // If repo.findAll() succeeds, it means all docs passed the Zod schemas for the profile
      // because OKFFileRepository uses OKFDocumentFactory and valid Zod parsing internally (or at least FrontmatterParser does profile validation if configured).
      // Actually, FrontmatterParser currently only validates against OKFFrontmatterSchema.
      // To strictly validate profile, we can use the domain/profiles/career schemas, but for now we rely on the parser not throwing OKFValidationError.
      report.passed += docs.length;
    } catch (e: any) {
      akcpCompatible = false;
      report.failed++;
      report.details.push({
        type: "error",
        message: `Profile Validation Error: ${e.message}`,
        ruleId: "AKCP-PROFILE-STRICT",
      });
    }

    if (!akcpCompatible) {
      return report;
    }
    report.conformanceLevel = "AKCP-profile-compatible";

    // Level 3: AKCP-compiler-compatible
    let compilerCompatible = true;
    try {
      // Build IR to test semantic graph and index integrity
      const ir = await buildKnowledgeIR(this.bundlePath, {
        sources: [{ type: "okf-directory", path: this.bundlePath }],
      });
      report.passed++;

      // Check for broken links (warnings)
      for (const link of ir.links || []) {
        const targetExists = ir.concepts.some(
          (c) => c.conceptId === link.targetConceptId,
        );
        if (!targetExists) {
          report.warnings++;
          report.details.push({
            file:
              ir.concepts.find((c) => c.conceptId === link.sourceConceptId)
                ?.source.filePath || link.sourceConceptId,
            type: "warning",
            message: `Broken dependency link: ${link.targetConceptId}`,
            ruleId: "AKCP-GRAPH-INTEGRITY",
          });
        }
      }
    } catch (e: any) {
      compilerCompatible = false;
      report.failed++;
      report.details.push({
        type: "error",
        message: `Compiler IR Error: ${e.message}`,
        ruleId: "AKCP-COMPILER-IR",
      });
    }

    if (!compilerCompatible) {
      return report;
    }
    report.conformanceLevel = "AKCP-compiler-compatible";

    // Level 4: AKCP-control-plane-compatible
    let controlPlaneCompatible = true;
    try {
      // If it has an akcp.yaml and valid policies
      const configPath = path.join(this.bundlePath, "akcp.yaml");
      if (await fsAdapter.exists(configPath)) {
        loadAkcpConfig(configPath); // Throws if invalid
        report.passed++;
      } else {
        // Warning if no config, but maybe we shouldn't fail?
        // Actually, to be control-plane compatible it MUST have an akcp.yaml
        controlPlaneCompatible = false;
        report.details.push({
          type: "warning",
          message: `No akcp.yaml found. Cannot verify control plane policies.`,
          ruleId: "AKCP-CP-CONFIG",
        });
      }
    } catch (e: any) {
      controlPlaneCompatible = false;
      report.failed++;
      report.details.push({
        type: "error",
        message: `Control Plane Config Error: ${e.message}`,
        ruleId: "AKCP-CP-CONFIG",
      });
    }

    if (controlPlaneCompatible) {
      report.conformanceLevel = "AKCP-control-plane-compatible";
    }

    return report;
  }
}

import { describe, it, expect, vi } from "vitest";
import { MCPGateway, MCPGatewayError } from "../../capabilities/gateway.js";
import type { PolicyCard } from "../../policy/types.js";

describe("MCPGateway", () => {
  const rawPolicy = {
    apiVersion: "policy.akcp.dev/v1alpha1",
    kind: "PolicyCard",
    metadata: { name: "test-policy" },
    spec: {
      allowedTools: ["read_document", "create_document"],
      forbiddenTools: ["delete_document"],
      sideEffectRules: {
        read: "allow",
        write: "allow",
        submit: "deny",
      },
      approvalRequirements: [],
      piiHandling: "redact",
    },
  };

  const mockPolicy: PolicyCard = rawPolicy as unknown as PolicyCard;

  const gateway = new MCPGateway({
    policies: {
      "agent-1": mockPolicy,
    },
    defaultPolicy: undefined,
  });

  it("should block execution if no valid policy is found for agent", async () => {
    await expect(
      gateway.execute(
        {
          requestId: "123",
          toolName: "read_document",
          sideEffect: "read",
          agentId: "unknown-agent",
          payload: {},
        },
        async () => ({ success: true }),
      ),
    ).rejects.toThrowError(MCPGatewayError);
  });

  it("should allow execution for allowed tool", async () => {
    const result = await gateway.execute(
      {
        requestId: "123",
        toolName: "read_document",
        sideEffect: "read",
        agentId: "agent-1",
        payload: {},
      },
      async () => ({ success: true }),
    );

    expect(result.success).toBe(true);
  });

  it("should block execution for forbidden tool", async () => {
    await expect(
      gateway.execute(
        {
          requestId: "123",
          toolName: "delete_document",
          sideEffect: "write",
          agentId: "agent-1",
          payload: {},
        },
        async () => ({ success: true }),
      ),
    ).rejects.toThrowError(/Policy Violation/);
  });

  it("should block execution for denied sideEffect", async () => {
    await expect(
      gateway.execute(
        {
          requestId: "123",
          toolName: "create_document", // allowed tool
          sideEffect: "submit", // but submit sideEffect is denied
          agentId: "agent-1",
          payload: {},
        },
        async () => ({ success: true }),
      ),
    ).rejects.toThrowError(/Policy Violation/);
  });

  it("should sanitize PII output when piiHandling is redact", async () => {
    const result = await gateway.execute(
      {
        requestId: "123",
        toolName: "read_document",
        sideEffect: "read",
        agentId: "agent-1",
        payload: {},
      },
      async () => ({
        email: "john.doe@example.com",
        ssn: "123-45-6789",
        name: "John Doe",
      }),
    );

    expect(result.email).toBe("[REDACTED_EMAIL]");
    expect(result.ssn).toBe("[REDACTED_SSN]");
    expect(result.name).toBe("John Doe"); // Unaffected
  });

  it("should throw error when piiHandling is deny and PII is found", async () => {
    const strictGateway = new MCPGateway({
      policies: {
        "agent-2": {
          ...mockPolicy,
          spec: {
            ...mockPolicy.spec,
            piiHandling: "deny",
          },
        },
      },
    });

    await expect(
      strictGateway.execute(
        {
          requestId: "123",
          toolName: "read_document",
          sideEffect: "read",
          agentId: "agent-2",
          payload: {},
        },
        async () => ({
          email: "john.doe@example.com",
        }),
      ),
    ).rejects.toThrowError(/PII detected in output/);
  });

  describe("HITL Approval Enforcement", () => {
    const approvalRequiredPolicy = {
      ...mockPolicy,
      spec: {
        ...mockPolicy.spec,
        allowedTools: ["restricted_tool"],
        approvalRequirements: ["restricted_tool"], // requires approval
      },
    };

    const mockApprovalStore = {
      generateToken: vi.fn().mockReturnValue("mock-token-123"),
      validateAndConsume: vi.fn().mockResolvedValue(true),
      getPendingApprovals: vi.fn(),
      getAuditLogs: vi.fn(),
      approveToken: vi.fn(),
      revokeToken: vi.fn(),
    };

    const hitlGateway = new MCPGateway({
      policies: {
        "agent-hitl": approvalRequiredPolicy as unknown as PolicyCard,
      },
      approvalStore: mockApprovalStore,
    });

    it("should throw APPROVAL_REQUIRED and generate token if no token is provided", async () => {
      let error: any;
      try {
        await hitlGateway.execute(
          {
            requestId: "123",
            toolName: "restricted_tool",
            sideEffect: "write",
            agentId: "agent-hitl",
            payload: { someData: "test" },
          },
          async () => ({ success: true }),
        );
      } catch (err) {
        error = err;
      }
      expect(error).toBeInstanceOf(MCPGatewayError);
      expect(error.code).toBe("APPROVAL_REQUIRED");
      expect(error.data.approvalToken).toBe("mock-token-123");
      expect(mockApprovalStore.generateToken).toHaveBeenCalledWith(
        expect.any(String), // requestId
        "restricted_tool",
        expect.any(String), // hash
        "high",
        "write",
        "agent-hitl",
        expect.any(Object)
      );
    });

    it("should execute successfully if a valid _approvalToken is provided", async () => {
      mockApprovalStore.validateAndConsume.mockResolvedValueOnce(true);
      const result = await hitlGateway.execute(
        {
          requestId: "124",
          toolName: "restricted_tool",
          sideEffect: "write",
          agentId: "agent-hitl",
          payload: { someData: "test", _approvalToken: "valid-token" },
        },
        async () => ({ success: true }),
      );

      expect(result.success).toBe(true);
      expect(mockApprovalStore.validateAndConsume).toHaveBeenCalledWith(
        "valid-token",
        "restricted_tool",
        expect.any(String), // hash
        "agent-hitl",
      );
    });

    it("should block execution if an invalid _approvalToken is provided", async () => {
      mockApprovalStore.validateAndConsume.mockResolvedValueOnce(false);
      await expect(
        hitlGateway.execute(
          {
            requestId: "125",
            toolName: "restricted_tool",
            sideEffect: "write",
            agentId: "agent-hitl",
            payload: { someData: "test", _approvalToken: "invalid-token" },
          },
          async () => ({ success: true }),
        ),
      ).rejects.toThrowError(/Invalid, expired, or tampered approval token/);
    });
  });
});

import { describe, it, expect, beforeEach } from "vitest";
import { MCPGateway } from "../capabilities/gateway.js";
import { InMemoryAuditLogService } from "../infrastructure/audit-log.js";
import type { IApprovalStore, PendingApproval } from "../capabilities/approval-store.js";
import type { PolicyCard } from "../policy/types.js";
import crypto from "crypto";

class MockApprovalStore implements IApprovalStore {
  private approvals: PendingApproval[] = [];

  async generateToken(
    requestId: string,
    capabilityId: string,
    payloadHash: string,
    riskLevel: string,
    sideEffectLevel: string,
    requestedBy: string,
    metadata?: Record<string, unknown>,
    ttlMs?: number
  ): Promise<string> {
    const token = "mock-token-123";
    this.approvals.push({
      token,
      requestId,
      capabilityId,
      payloadHash,
      riskLevel,
      sideEffectLevel,
      requestedBy,
      createdAt: Date.now(),
      expiresAt: Date.now() + (ttlMs || 60000),
      status: "PENDING",
      auditEventIds: [],
      metadata
    });
    return token;
  }

  async getPendingApprovals(): Promise<PendingApproval[]> {
    return this.approvals;
  }

  async getAuditLogs(limit?: number): Promise<any[]> {
    return [];
  }

  async approveToken(token: string, actorIdentity?: string): Promise<boolean> {
    const app = this.approvals.find(a => a.token === token);
    if (app && app.status === "PENDING") {
      app.status = "APPROVED";
      app.approvedBy = actorIdentity;
      return true;
    }
    return false;
  }

  async validateAndConsume(token: string, capabilityId: string, payloadHash: string, actorIdentity?: string): Promise<boolean> {
    const app = this.approvals.find(a => a.token === token);
    if (app && app.status === "APPROVED" && app.capabilityId === capabilityId && app.payloadHash === payloadHash) {
      app.status = "CONSUMED";
      app.consumedAt = Date.now();
      return true;
    }
    return false;
  }

  async revokeToken(token: string, actorIdentity?: string): Promise<boolean> {
    const app = this.approvals.find(a => a.token === token);
    if (app && app.status === "PENDING") {
      app.status = "REVOKED";
      return true;
    }
    return false;
  }
}

describe("Control Plane & Runtime Governance", () => {
  let auditLog: InMemoryAuditLogService;
  let approvalStore: MockApprovalStore;
  let gateway: MCPGateway;

  const policyAllowAll: PolicyCard = {
    metadata: { name: "allow-all" },
    appliesTo: { capabilities: ["*"] },
    rules: [{ effect: "allow" }]
  };

  const policyDenyAll: PolicyCard = {
    metadata: { name: "deny-all" },
    appliesTo: { capabilities: ["*"] },
    rules: [{ effect: "deny" }]
  };

  const policyRequiresApproval: PolicyCard = {
    metadata: { name: "require-approval" },
    appliesTo: { capabilities: ["akcp.external_submit"] },
    rules: [{ effect: "require_approval" }]
  };

  beforeEach(() => {
    auditLog = new InMemoryAuditLogService();
    approvalStore = new MockApprovalStore();
  });

  it("should allow execution and emit policy-allow audit event", async () => {
    gateway = new MCPGateway({
      policies: { "agent-1": policyAllowAll },
      auditLogService: auditLog
    });

    const result = await gateway.execute(
      { agentId: "agent-1", toolName: "akcp.read_document", sideEffect: "read", payload: {} },
      async () => "success"
    );

    expect(result).toBe("success");
    const events = await auditLog.getEvents();
    expect(events).toHaveLength(1);
    expect(events[0].decision).toBe("allow");
  });

  it("should block execution and emit policy-deny audit event", async () => {
    gateway = new MCPGateway({
      policies: { "agent-1": policyDenyAll },
      auditLogService: auditLog
    });

    await expect(gateway.execute(
      { agentId: "agent-1", toolName: "akcp.read_document", sideEffect: "read", payload: {} },
      async () => "success"
    )).rejects.toThrow("Policy Violation");

    const events = await auditLog.getEvents();
    expect(events).toHaveLength(1);
    expect(events[0].decision).toBe("deny");
  });

  it("should pause execution, require approval, and resume when token is provided", async () => {
    gateway = new MCPGateway({
      policies: { "agent-1": policyRequiresApproval },
      auditLogService: auditLog,
      approvalStore
    });

    const payload = { data: "test" };

    // 1. Initial attempt fails with APPROVAL_REQUIRED
    let generatedToken = "";
    try {
      await gateway.execute(
        { agentId: "agent-1", toolName: "akcp.external_submit", sideEffect: "submit", payload },
        async () => "success"
      );
      expect.fail("Should have thrown APPROVAL_REQUIRED");
    } catch (err: any) {
      expect(err.code).toBe("APPROVAL_REQUIRED");
      generatedToken = err.data.approvalToken;
    }

    // Check Audit logs for approval requirement
    let events = await auditLog.getEvents();
    expect(events.map(e => e.decision)).toContain("require_approval");

    // 2. Approve token out of band
    await approvalStore.approveToken(generatedToken, "human-approver");

    // 3. Resume execution with token
    const result = await gateway.execute(
      { agentId: "agent-1", toolName: "akcp.external_submit", sideEffect: "submit", payload: { ...payload, _approvalToken: generatedToken } },
      async () => "success"
    );

    expect(result).toBe("success");

    events = await auditLog.getEvents();
    expect(events.map(e => e.decision)).toContain("consumed");
  });

  it("should block execution if payload hash does not match approval token", async () => {
    gateway = new MCPGateway({
      policies: { "agent-1": policyRequiresApproval },
      auditLogService: auditLog,
      approvalStore
    });

    const payload = { data: "test" };

    // 1. Initial attempt fails with APPROVAL_REQUIRED
    let generatedToken = "";
    try {
      await gateway.execute(
        { agentId: "agent-1", toolName: "akcp.external_submit", sideEffect: "submit", payload },
        async () => "success"
      );
      expect.fail("Should have thrown APPROVAL_REQUIRED");
    } catch (err: any) {
      generatedToken = err.data.approvalToken;
    }

    // 2. Approve token out of band
    await approvalStore.approveToken(generatedToken, "human-approver");

    // 3. Attempt execution with token but MODIFIED payload
    const modifiedPayload = { data: "malicious-change", _approvalToken: generatedToken };

    await expect(gateway.execute(
      { agentId: "agent-1", toolName: "akcp.external_submit", sideEffect: "submit", payload: modifiedPayload },
      async () => "success"
    )).rejects.toThrow("Invalid, expired, or tampered approval token");

    const events = await auditLog.getEvents();
    expect(events.map(e => e.decision)).toContain("expired"); // Maps to invalid/expired
  });

  it("should rate limit excessive requests", async () => {
    gateway = new MCPGateway({
      policies: { "agent-1": policyAllowAll },
      auditLogService: auditLog,
      rateLimiter: { maxTokens: 3, refillRate: 1 },
    });

    // First 3 should succeed
    for (let i = 0; i < 3; i++) {
      await gateway.execute(
        { agentId: "agent-1", toolName: "akcp.read_document", sideEffect: "read", payload: {} },
        async () => "success",
      );
    }

    // 4th should be rate limited
    await expect(
      gateway.execute(
        { agentId: "agent-1", toolName: "akcp.read_document", sideEffect: "read", payload: {} },
        async () => "success",
      ),
    ).rejects.toThrow("Rate limit exceeded");
  });
});

describe("Authentication", () => {
  it("should reject unauthenticated requests when auth is configured", async () => {
    const policyAllowAll = {
      metadata: { name: "allow-all" },
      appliesTo: { capabilities: ["*"] },
      rules: [{ effect: "allow" as const }]
    };

    const authGateway = new MCPGateway({
