/**
 * @module __tests__/okf-file-repository.test
 * @description Unit tests for OKFFileRepository with mocked IFileSystemAdapter.
 *
 * Uses a REAL FrontmatterParser (pure, no I/O) and a vi.fn()-based mock for
 * IFileSystemAdapter. This approach validates the integration between the
 * repository's orchestration logic and the parser's validation, while keeping
 * the tests deterministic and fast (no filesystem access).
 *
 * Mock data uses realistic career document content to ensure frontmatter
 * schemas are exercised end-to-end.
 */

import { describe, it, expect, vi, beforeEach } from "vitest";

import type { IFileSystemAdapter } from "../domain/interfaces.js";
import { OKFValidationError, OKFFileNotFoundError } from "../domain/errors.js";
import { FrontmatterParser } from "../infrastructure/frontmatter-parser.js";
import { OKFFileRepository } from "../repositories/okf-file-repository.js";

// ─── Fixtures ───────────────────────────────────────────────────────────────────

const BUNDLE_ROOT = "/home/user/career-bundle";

/** A valid Skill document. */
const SKILL_CONTENT = [
  "---",
  "type: Skill",
  "title: TypeScript",
  "level: Advanced",
  "yearsOfExperience: 5",
  "category: Programming Languages",
  "tags:",
  "  - frontend",
  "  - backend",
  "---",
  "",
  "# TypeScript",
  "",
  "Expert-level TypeScript developer with 5 years of production experience.",
].join("\n");

/** A valid Experience document. */
const EXPERIENCE_CONTENT = [
  "---",
  "type: Experience",
  "title: Senior Engineer at Acme Corp",
  "company: Acme Corp",
  "role: Senior Engineer",
  'startDate: "2021-03-01"',
  'endDate: "2024-06-30"',
  "location: San Francisco, CA",
  "tags:",
  "  - full-time",
  "---",
  "",
  "# Senior Engineer at Acme Corp",
  "",
  "Led a team of 8 engineers building distributed systems.",
].join("\n");

/** A valid Application document. */
const APPLICATION_CONTENT = [
  "---",
  "type: Application",
  "title: Staff Engineer at BigTech",
  "company: BigTech",
  "position: Staff Engineer",
  "url: https://careers.bigtech.com/12345",
  "applicationStatus: Applied",
  "platform: LinkedIn",
  "---",
  "",
  "# Staff Engineer at BigTech",
  "",
  "Applied for the Staff Engineer role via LinkedIn.",
].join("\n");

/** Content with invalid/missing type field. */
const INVALID_CONTENT = [
  "---",
  "title: Missing Type",
  "---",
  "",
  "This document has no type field.",
].join("\n");

/** Content with malformed YAML. */
const MALFORMED_CONTENT = [
  "---",
  "type: Skill",
  "bad: [unclosed",
  "---",
  "",
  "Body.",
].join("\n");

// ─── Mock Factory ───────────────────────────────────────────────────────────────

function createMockFileSystemAdapter(): IFileSystemAdapter {
  return {
    readFile: vi.fn<(filePath: string) => Promise<string>>(),
    writeFile: vi
      .fn<(filePath: string, content: string) => Promise<void>>()
      .mockResolvedValue(undefined),
    exists: vi.fn<(filePath: string) => Promise<boolean>>(),
    mkdir: vi
      .fn<(dirPath: string) => Promise<void>>()
      .mockResolvedValue(undefined),
    deleteFile: vi
      .fn<(filePath: string) => Promise<void>>()
      .mockResolvedValue(undefined),
    listFiles:
      vi.fn<(dirPath: string, pattern?: string) => Promise<string[]>>(),
  };
}

// ─── Tests ──────────────────────────────────────────────────────────────────────

describe("OKFFileRepository", () => {
  let mockFs: ReturnType<typeof createMockFileSystemAdapter>;
  let parser: FrontmatterParser;
  let repository: OKFFileRepository;

  beforeEach(() => {
    mockFs = createMockFileSystemAdapter();
    parser = new FrontmatterParser();
    repository = new OKFFileRepository(mockFs, parser, BUNDLE_ROOT);
  });

  // ─── findById ─────────────────────────────────────────────────────────────

  it("should find document by concept ID", async () => {
    vi.mocked(mockFs.exists).mockResolvedValue(true);
    vi.mocked(mockFs.readFile).mockResolvedValue(SKILL_CONTENT);

    const doc = await repository.findById("skills/typescript");

    expect(doc).not.toBeNull();
    expect(doc!.frontmatter.type).toBe("Skill");
    expect(doc!.frontmatter.title).toBe("TypeScript");
    expect(doc!.conceptId).toBe("skills/typescript");
    expect(mockFs.readFile).toHaveBeenCalledWith(
      expect.stringContaining("skills"),
    );
  });

  it("should return null for non-existent concept ID", async () => {
    vi.mocked(mockFs.exists).mockResolvedValue(false);

    const doc = await repository.findById("skills/nonexistent");

    expect(doc).toBeNull();
  });

  // ─── findAll ──────────────────────────────────────────────────────────────

  it("should find all documents excluding reserved files", async () => {
    vi.mocked(mockFs.listFiles).mockResolvedValue([
      "skills/typescript.md",
      "experiences/acme-corp.md",
      "index.md",
      "log.md",
    ]);
    vi.mocked(mockFs.readFile)
      .mockResolvedValueOnce(SKILL_CONTENT)
      .mockResolvedValueOnce(EXPERIENCE_CONTENT);

    const docs = await repository.findAll();

    // index.md and log.md should be excluded
    expect(docs).toHaveLength(2);
    expect(docs[0].frontmatter.type).toBe("Skill");
    expect(docs[1].frontmatter.type).toBe("Experience");
  });

  // ─── findByType ───────────────────────────────────────────────────────────

  it("should find documents by type", async () => {
    vi.mocked(mockFs.listFiles).mockResolvedValue([
      "skills/typescript.md",
      "experiences/acme-corp.md",
      "applications/bigtech.md",
    ]);
    vi.mocked(mockFs.readFile)
      .mockResolvedValueOnce(SKILL_CONTENT)
      .mockResolvedValueOnce(EXPERIENCE_CONTENT)
      .mockResolvedValueOnce(APPLICATION_CONTENT);

    const docs = await repository.findByType("Experience");

    expect(docs).toHaveLength(1);
    expect(docs[0].frontmatter.type).toBe("Experience");
    expect(docs[0].frontmatter["company"]).toBe("Acme Corp");
  });

  // ─── save ─────────────────────────────────────────────────────────────────

  it("should save document with valid frontmatter", async () => {
    const doc = {
      frontmatter: {
        type: "Skill",
        title: "Python",
        tags: ["backend", "data-science"],
      },
      body: "# Python\n\nVersatile programming language.",
      filePath: "",
      conceptId: "skills/python",
    };

    await repository.save(doc);

    expect(mockFs.writeFile).toHaveBeenCalledTimes(1);
    const [writtenPath, writtenContent] = vi.mocked(mockFs.writeFile).mock
      .calls[0];
    expect(writtenPath).toContain("skills");
    expect(writtenPath).toContain("python.md");
    expect(writtenContent).toContain("type: Skill");
    expect(writtenContent).toContain("title: Python");
    expect(writtenContent).toContain("# Python");
  });

  it("should throw OKFValidationError when saving document without type", async () => {
    const doc = {
      frontmatter: {
        type: "",
        title: "Invalid",
      },
      body: "No type field.",
      filePath: "",
      conceptId: "bad/invalid",
    };

    await expect(repository.save(doc)).rejects.toThrow(OKFValidationError);
    expect(mockFs.writeFile).not.toHaveBeenCalled();
  });

  // ─── delete ───────────────────────────────────────────────────────────────

  it("should delete existing document", async () => {
    vi.mocked(mockFs.exists).mockResolvedValue(true);

    await repository.delete("skills/typescript");

    expect(mockFs.deleteFile).toHaveBeenCalledTimes(1);
    expect(mockFs.deleteFile).toHaveBeenCalledWith(
      expect.stringContaining("typescript.md"),
    );
  });

  it("should throw OKFFileNotFoundError when deleting non-existent document", async () => {
    vi.mocked(mockFs.exists).mockResolvedValue(false);

    await expect(repository.delete("skills/ghost")).rejects.toThrow(
      OKFFileNotFoundError,
    );
    expect(mockFs.deleteFile).not.toHaveBeenCalled();
  });

  // ─── Error Handling ───────────────────────────────────────────────────────

  it("should handle parse errors gracefully in findAll", async () => {
    vi.mocked(mockFs.listFiles).mockResolvedValue([
      "skills/typescript.md",
      "skills/broken.md",
    ]);
    vi.mocked(mockFs.readFile)
      .mockResolvedValueOnce(SKILL_CONTENT)
      .mockResolvedValueOnce(MALFORMED_CONTENT);

    // findAll should skip unparseable documents rather than throwing
    const docs = await repository.findAll();

    expect(docs).toHaveLength(1);
    expect(docs[0].frontmatter.type).toBe("Skill");
  });
});

import { describe, it, expect } from "vitest";
import {
  PluginLoader,
  PluginSecurityError,
  PluginValidationError,
} from "../../plugins/loader.js";
import * as path from "path";

describe("PluginLoader", () => {
  it("throws PluginValidationError if manifest is missing", async () => {
    const fakeDir = path.resolve(__dirname, "non-existent");
    expect(() => PluginLoader.loadManifest(fakeDir)).toThrow(
      PluginValidationError,
    );
  });

  it("throws PluginSecurityError if plugin lacks required permissions", async () => {
    // We mock a directory by relying on the real example plugin which has fs:read
    // but not network:outbound
    const exampleDir = path.resolve(
      __dirname,
      "../__fixtures__/plugins/example-markdown-connector",
    );

    // Test passes if the directory exists (which it should in the workspace)
    try {
      await PluginLoader.loadPlugin(exampleDir, ["network:outbound"]);
      expect.fail("Should have thrown security error");
    } catch (err: any) {
      expect(err).toBeInstanceOf(PluginSecurityError);
      expect(err.message).toContain("network:outbound");
    }
  });

  it("loads successfully if permissions match", async () => {
    const exampleDir = path.resolve(
      __dirname,
      "../__fixtures__/plugins/example-markdown-connector",
    );

    try {
      // example-markdown-connector has fs:read
      const { manifest } = await PluginLoader.loadPlugin(exampleDir, [
        "fs:read",
      ]);
      expect(manifest.name).toBe("example-markdown-connector");
    } catch (err: any) {
      // This will fail if the module can't be imported, which is fine, we mainly test the security check here.
      if (err instanceof PluginSecurityError) {
        expect.fail("Should not throw security error for declared permissions");
      }
    }
  });
});

import { describe, it, expect, vi, beforeEach } from "vitest";
import { HttpSecurityGateway } from "../../privacy/http-security-gateway.js";

describe("HttpSecurityGateway", () => {
  beforeEach(() => {
    vi.restoreAllMocks();
  });

  it("should successfully redact text via external gateway", async () => {
    const mockResponse = {
      redactedText: "Hello <REDACTED_PERSON>",
      findings: [{ type: "PERSON", start: 6, end: 11, score: 0.99 }],
      blocked: false,
    };

    global.fetch = vi.fn().mockResolvedValue({
      ok: true,
      json: async () => mockResponse,
    } as any);

    const gateway = new HttpSecurityGateway("http://localhost:8080/redact", "<REDACTED_{class}>");
    const result = await gateway.redact("Hello Alice", { mode: "redact" });

    expect(result.redactedText).toBe("Hello <REDACTED_PERSON>");
    expect(result.findings.length).toBe(1);
    expect(result.blocked).toBe(false);
    expect(fetch).toHaveBeenCalledWith("http://localhost:8080/redact", expect.objectContaining({
      method: "POST",
      body: expect.stringContaining("Hello Alice")
    }));
  });

  it("should throw an error if the gateway is unreachable or returns a non-200 status", async () => {
    global.fetch = vi.fn().mockResolvedValue({
      ok: false,
      status: 500,
      statusText: "Internal Server Error",
    } as any);

    const gateway = new HttpSecurityGateway("http://localhost:8080/redact");

    await expect(gateway.redact("Hello Alice", { mode: "redact" }))
      .rejects.toThrow(/Failed to reach Security Gateway/);
  });
});

import { describe, it, expect } from "vitest";
import { hashString, hashConfig } from "../../provenance/hash.js";
import path from "path";

describe("Provenance Hashing", () => {
  it("should generate consistent SHA-256 hashes for strings", () => {
    const data = "hello world";
    const hash1 = hashString(data);
    const hash2 = hashString(data);
    expect(hash1).toBe(hash2);
    // Known SHA-256 for 'hello world'
    expect(hash1).toBe(
      "b94d27b9934d3e08a52e52d7da7dabfac484efe37a5380ee9088f7ace2efcde9",
    );
  });

  it("should generate consistent hashes for configs with redacted secrets", () => {
    const config1 = {
      compile: {
        targets: ["mcp-profile-server"],
        some_api_key: "real-secret-123",
      },
    };

    const config2 = {
      compile: {
        some_api_key: "different-secret-456",
        targets: ["mcp-profile-server"], // different key order
      },
    };

    const hash1 = hashConfig(config1);
    const hash2 = hashConfig(config2);

    // Because keys are sorted and secrets are redacted to '[REDACTED]', they should hash identically.
    expect(hash1).toBe(hash2);
  });
});

import { describe, it, expect, beforeEach, afterEach } from "vitest";
import { verifyManifest } from "../../provenance/verify.js";
import { ProvenanceManifestBuilder } from "../../provenance/build-manifest.js";
import fs from "node:fs/promises";
import path from "node:path";
import { hashFile } from "../../provenance/hash.js";

describe("Provenance Verification", () => {
  const testDir = path.resolve(process.cwd(), "dist/test-provenance");
  const manifestPath = path.join(testDir, "akcp-manifest.json");
  const mockArtifactPath = path.join(testDir, "mock-target.txt");

  beforeEach(async () => {
    await fs.mkdir(testDir, { recursive: true });
  });

  afterEach(async () => {
    await fs.rm(testDir, { recursive: true, force: true });
  });

  it("should verify a valid manifest successfully", async () => {
    // 1. Create a dummy artifact
    await fs.writeFile(mockArtifactPath, "Hello Provenance!", "utf-8");
    const artifactHash = await hashFile(mockArtifactPath);

    // 2. Build the manifest
    const builder = new ProvenanceManifestBuilder();
    builder.addOutput({
      targetType: "test-target",
      outputPath: "dist/test-provenance/mock-target.txt",
      hash: artifactHash,
      bytesWritten: 17,
    });

    const irMock = {
      buildId: "bld_123",
      bundleId: "test_bundle",
      timestamp: new Date().toISOString(),
      concepts: [],
    } as any;

    await builder.writeManifest(
      irMock,
      "dist/test-provenance/akcp-manifest.json",
      "hash123",
      "0.1.0",
    );

    // 3. Verify
    const report = await verifyManifest(
      "dist/test-provenance/akcp-manifest.json",
    );
    expect(report.isValid).toBe(true);
    expect(report.tamperedFiles).toHaveLength(0);
    expect(report.missingFiles).toHaveLength(0);
  });

  it("should fail verification if a file is tampered", async () => {
    // 1. Create a dummy artifact
    await fs.writeFile(mockArtifactPath, "Hello Provenance!", "utf-8");
    const artifactHash = await hashFile(mockArtifactPath);

    // 2. Build the manifest
    const builder = new ProvenanceManifestBuilder();
    builder.addOutput({
      targetType: "test-target",
      outputPath: "dist/test-provenance/mock-target.txt",
      hash: artifactHash,
      bytesWritten: 17,
    });

    const irMock = {
      buildId: "bld_123",
      bundleId: "test_bundle",
      timestamp: new Date().toISOString(),
      concepts: [],
    } as any;

    await builder.writeManifest(
      irMock,
      "dist/test-provenance/akcp-manifest.json",
      "hash123",
      "0.1.0",
    );

    // 3. Tamper with the artifact
    await fs.writeFile(mockArtifactPath, "Hello TAMPERED!", "utf-8");

    // 4. Verify
    const report = await verifyManifest(
      "dist/test-provenance/akcp-manifest.json",
    );
    expect(report.isValid).toBe(false);
    expect(report.tamperedFiles).toContain(
      "dist/test-provenance/mock-target.txt",
    );
  });

  it("should fail verification if a file is missing", async () => {
    // 1. Create a dummy artifact
    await fs.writeFile(mockArtifactPath, "Hello Provenance!", "utf-8");
    const artifactHash = await hashFile(mockArtifactPath);

    // 2. Build the manifest
    const builder = new ProvenanceManifestBuilder();
    builder.addOutput({
      targetType: "test-target",
      outputPath: "dist/test-provenance/mock-target.txt",
      hash: artifactHash,
      bytesWritten: 17,
    });

    const irMock = {
      buildId: "bld_123",
      bundleId: "test_bundle",
      timestamp: new Date().toISOString(),
      concepts: [],
    } as any;

    await builder.writeManifest(
      irMock,
      "dist/test-provenance/akcp-manifest.json",
      "hash123",
      "0.1.0",
    );

    // 3. Delete the artifact
    await fs.rm(mockArtifactPath);

    // 4. Verify
    const report = await verifyManifest(
      "dist/test-provenance/akcp-manifest.json",
    );
    expect(report.isValid).toBe(false);
    expect(report.missingFiles).toContain(
      "dist/test-provenance/mock-target.txt",
    );
  });
});

import { describe, it, expect } from "vitest";
import { calculateScorecard } from "../../scorecard/calculate.js";
import { ScorecardDimension } from "../../scorecard/types.js";
