}

#!/usr/bin/env tsx
/**
 * @module cli/migrate-bundle
 * @description Command line utility to run OKF bundle migrations.
 */

import path from "node:path";
import { FileSystemAdapter } from "../infrastructure/file-system-adapter.js";
import { FrontmatterParser } from "../infrastructure/frontmatter-parser.js";
import { migrateBundle } from "../migrations/migrate-bundle.js";

async function main() {
  const args = process.argv.slice(2);
  const write = args.includes("--write");
  const backup = args.includes("--backup");

  // Filter out flags to get target path
  const targetArg = args.find((a) => !a.startsWith("--"));
  const bundlePathEnv = targetArg || process.env["AKCP_BUNDLE_PATH"] || "./.okf";
  const bundlePath = path.resolve(bundlePathEnv);

  console.log(`[AKCP Migrator] Starting migration pipeline at: ${bundlePath}`);
  console.log(`  Flags: write=${write}, backup=${backup}`);

  const fsAdapter = new FileSystemAdapter();
  const fmParser = new FrontmatterParser();

  const report = await migrateBundle(fsAdapter, fmParser, bundlePath, {
    write,
    backup,
  });

  if (!report.success) {
    console.error(`[AKCP Migrator] Fatal migration failure: ${report.error}`);
    process.exit(1);
  }

  console.log(`\n[AKCP Migrator] Run summary:`);
  console.log(`  Files checked: ${report.filesChecked}`);
  console.log(`  Files needing migration: ${report.filesNeedingMigration}`);
  console.log(`  Files migrated: ${report.filesMigrated}`);

  if (report.backupPath) {
    console.log(`  Backup created at: ${report.backupPath}`);
  }

  if (report.filesNeedingMigration > 0 && !write) {
    console.log(
      `\n[AKCP Migrator] WARNING: Legacy files detected. Re-run with '--write' to execute migrations.`,
    );
  }

  process.exit(0);
}

main().catch((err) => {
  console.error("[AKCP Migrator] Unhandled exception:", err);
  process.exit(1);
});

#!/usr/bin/env tsx
/**
 * @module cli/validate-bundle
 * @description Command line utility to validate OKF bundle schemas.
 */

import path from "node:path";
import { FileSystemAdapter } from "../infrastructure/file-system-adapter.js";
import { FrontmatterParser } from "../infrastructure/frontmatter-parser.js";
import { ProfileRegistry } from "../domain/schemas.js";
import { OKFValidationError } from "../domain/errors.js";

type BundleValidationReport = {
  ok: boolean;
  bundlePath: string;
  checkedAt: string;
  profile: string;
  summary: {
    filesChecked: number;
    validDocuments: number;
    invalidDocuments: number;
    warnings: number;
  };
  diagnostics: Array<{
    severity: "error" | "warning" | "info";
    file: string;
    code: string;
    message: string;
    field?: string;
    suggestion?: string;
  }>;
};

async function main() {
  const args = process.argv.slice(2);
  let bundlePathEnv = process.env["AKCP_BUNDLE_PATH"] || "./.okf";
  let format: "text" | "json" | "markdown" = "text";
  let profileName = "career"; // default to legacy behavior

  for (let i = 0; i < args.length; i++) {
    const currentArg = args[i];
    if (currentArg === "--bundle" && i + 1 < args.length) {
      bundlePathEnv = args[i + 1]!;
    } else if (currentArg === "--format" && i + 1 < args.length) {
      format = args[i + 1] as any;
    } else if (currentArg === "--profile" && i + 1 < args.length) {
      profileName = args[i + 1]!;
    } else if (
      currentArg !== undefined &&
      !currentArg.startsWith("--") &&
      i === 0 &&
      !args.includes("--bundle")
    ) {
      bundlePathEnv = currentArg;
    }
  }

  const bundlePath = path.resolve(bundlePathEnv);
  const SchemaValidator = ProfileRegistry.getProfileSchema(profileName);

  const fsAdapter = new FileSystemAdapter();
  const fmParser = new FrontmatterParser();

  if (!(await fsAdapter.exists(bundlePath))) {
    console.error(`Error: Directory does not exist: ${bundlePath}`);
    process.exit(1);
  }

  const relativeFiles = await fsAdapter.listFiles(bundlePath);
  const RESERVED_FILENAMES = new Set(["index.md", "log.md", "README.md", "WALKTHROUGH.md"]);

  let validCount = 0;
  let invalidCount = 0;
  let skippedCount = 0;
  const diagnostics: BundleValidationReport["diagnostics"] = [];

  for (const relPath of relativeFiles) {
    if (
      !relPath.endsWith(".md") ||
      RESERVED_FILENAMES.has(path.basename(relPath))
    ) {
      continue;
    }

    const fullPath = path.join(bundlePath, relPath);
    const content = await fsAdapter.readFile(fullPath);

    try {
      const doc = fmParser.parse(content, fullPath, bundlePath);
      const validation = SchemaValidator.safeParse(doc.frontmatter);

      if (validation.success) {
        validCount++;
      } else {
        invalidCount++;
        diagnostics.push({
          severity: "error",
          file: relPath,
          code: "SCHEMA_INVALID",
          message: validation.error.message,
        });
      }
    } catch (err: any) {
      // If a file has no OKF frontmatter (e.g., a policy redirect or scenario file),
      // treat it as a skipped warning rather than a validation failure.
      if (err instanceof OKFValidationError) {
        skippedCount++;
        console.warn(
          `[AKCP Validator] Skipping "${path.basename(relPath)}": ${err.message}`,
        );
        continue;
      }
      invalidCount++;
      diagnostics.push({
        severity: "error",
        file: relPath,
        code: "PARSE_ERROR",
        message: err.message,
      });
    }
  }

  const report: BundleValidationReport = {
    ok: invalidCount === 0,
    bundlePath,
    checkedAt: new Date().toISOString(),
    profile: profileName,
    summary: {
      filesChecked: validCount + invalidCount,
      validDocuments: validCount,
      invalidDocuments: invalidCount,
      warnings: 0,
    },
    diagnostics,
  };

  if (format === "json") {
    console.log(JSON.stringify(report, null, 2));
  } else if (format === "markdown") {
    console.log(`# Bundle Validation Report\n`);
    console.log(`- **Checked At:** ${report.checkedAt}`);
    console.log(`- **Bundle Path:** ${report.bundlePath}`);
    console.log(`- **Profile:** ${report.profile}`);
    console.log(`- **Status:** ${report.ok ? "✅ Valid" : "❌ Invalid"}`);
    console.log(`\n## Summary\n`);
    console.log(`- Files Checked: ${report.summary.filesChecked}`);
    console.log(`- Valid Documents: ${report.summary.validDocuments}`);
    console.log(`- Invalid Documents: ${report.summary.invalidDocuments}`);
    if (diagnostics.length > 0) {
      console.log(`\n## Diagnostics\n`);
      for (const d of diagnostics) {
        console.log(
          `- **[${d.severity.toUpperCase()}]** \`${d.file}\`: ${d.message}`,
        );
      }
    }
  } else {
    console.log(
      `[AKCP Validator] Scanning bundle at: ${bundlePath} (Profile: ${profileName})`,
    );
    for (const d of diagnostics) {
      console.error(`  ✗ [Invalid] ${d.file}:`);
      console.error(`    Reason: ${d.message}`);
    }
    console.log(`\n[AKCP Validator] Validation summary:`);
    console.log(`  Valid concepts: ${validCount}`);
    console.log(`  Invalid concepts: ${invalidCount}`);
    if (report.ok) {
      console.log(
        `[AKCP Validator] All checked records are strictly schema compliant!`,
      );
    }
  }

  if (!report.ok) {
    process.exit(1);
  } else {
    process.exit(0);
  }
}

main().catch((err) => {
  console.error("[AKCP Validator] Unhandled exception:", err);
  process.exit(1);
});

import fs from "node:fs";
import path from "node:path";

export type IncrementalBuildState = {
  sourceHash: string;
  normalizedHash: string;
  artifactHash: string;
  lastCompiledAt: string;
  dependencies: string[];
};

export type BuildStateCache = Record<string, IncrementalBuildState>;

export class IncrementalCompiler {
  private stateFile: string;
  private state: BuildStateCache = {};

  constructor(workspaceDir: string) {
    let resolvedDir = workspaceDir;
    try {
      if (fs.existsSync(workspaceDir) && fs.statSync(workspaceDir).isFile()) {
        resolvedDir = path.dirname(workspaceDir);
      }
    } catch (e) {
      // Ignore
    }

    this.stateFile = path.join(
      resolvedDir,
      ".akcp",
      "cache",
      "build-state.json",
    );
    this.loadState();
  }

  private loadState() {
    try {
      if (fs.existsSync(this.stateFile)) {
        const raw = fs.readFileSync(this.stateFile, "utf-8");
        this.state = JSON.parse(raw);
      }
    } catch (e) {
      this.state = {};
    }
  }

  public saveState() {
    try {
      const dir = path.dirname(this.stateFile);
      if (!fs.existsSync(dir)) {
        fs.mkdirSync(dir, { recursive: true });
      }
      fs.writeFileSync(
        this.stateFile,
        JSON.stringify(this.state, null, 2),
        "utf-8",
      );
    } catch (e) {
      console.warn("[WARN] Failed to save incremental build state.", e);
    }
  }

  public shouldCompile(fileUri: string, currentHash: string): boolean {
    const cached = this.state[fileUri];
    if (!cached) return true;
    return cached.sourceHash !== currentHash;
  }

  public updateState(
    fileUri: string,
    currentHash: string,
    artifactHash: string,
    dependencies: string[] = [],
  ) {
    this.state[fileUri] = {
      sourceHash: currentHash,
      normalizedHash: "", // reserved for mid-step hashing
      artifactHash,
      lastCompiledAt: new Date().toISOString(),
      dependencies,
    };
  }

  public getState(fileUri: string): IncrementalBuildState | undefined {
    return this.state[fileUri];
  }
}

