import type { PipelineContext, PipelineStage } from "./pipeline.js";
import type { AgentKnowledgeIR } from "../ir/types.js";
import type { BuildOptions } from "../ir/build-ir.js";
import { basename } from "path";
import { randomUUID } from "crypto";
import { IngestStage } from "./stages/ingest.js";
import { NormalizeStage } from "./stages/normalize.js";
import { PrivacyStage } from "./stages/privacy.js";
import { EnrichStage } from "./stages/enrich.js";
import { LinkExtractStage } from "./stages/link-extract.js";
import { ValidateStage } from "./stages/validate.js";
import { LifecycleValidator } from "../validation/lifecycle-rules.js";
import { CapabilityValidator } from "../validation/capability-rules.js";

const DEFAULT_STAGES: PipelineStage[] = [
  new IngestStage(),
  new NormalizeStage(),
  new PrivacyStage(),
  new EnrichStage(),
  new LinkExtractStage(),
  new ValidateStage(),
];

export async function runCompilerPipeline(
  bundlePath: string,
  options: BuildOptions = {},
  stages: PipelineStage[] = DEFAULT_STAGES,
): Promise<AgentKnowledgeIR> {
  let context: PipelineContext = {
    bundlePath,
    options,
    rawItems: [],
    concepts: [],
    links: [],
    sourceHashes: {},
    skippedCount: 0,
  };

  for (const stage of stages) {
    context = await stage.execute(context);
  }

  const ir: AgentKnowledgeIR = {
    irVersion: "1.0.0",
    okfVersion: "0.1.0",
    bundleId: options.bundleId || basename(bundlePath),
    buildId: `bld_${randomUUID().split("-")[0]}`,
    timestamp: new Date().toISOString(),
    concepts: context.concepts,
    links: context.links,
    policies: options.policies,
    capabilities: options.capabilities || [],
    targets: options.targets || ["mcp-profile-server", "mcp-automation-server"],
    sourceHashes: context.sourceHashes,
  };

  LifecycleValidator.validate(ir);
  if (ir.capabilities && ir.capabilities.length > 0) {
    CapabilityValidator.validate(ir.capabilities as any);
  }

  return ir;
}

import fs from "node:fs";
import yaml from "yaml";
import { z } from "zod";
import { AkcpConfigSchema, CompileConfigSchema, ControlPlaneConfigSchema, type AkcpConfig } from "./akcp-config-schema.js";

export class ConfigLoadError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "ConfigLoadError";
  }
}

export function loadAkcpConfig(filePath: string): AkcpConfig {
  if (!fs.existsSync(filePath)) {
    throw new ConfigLoadError(`Configuration file not found: ${filePath}`);
  }

  const fileContent = fs.readFileSync(filePath, "utf-8");

  let parsedYaml: any;
  try {
    parsedYaml = yaml.parse(fileContent);
  } catch (error: any) {
    throw new ConfigLoadError(
      `Failed to parse YAML file at ${filePath}:\n${error.message}`,
    );
  }

  try {
    const config = AkcpConfigSchema.parse(parsedYaml);

    // Normalize root-level definitions to compile/controlPlane
    if (!config.compile && (config.sources || config.targets)) {
      config.compile = {
        sources: config.sources || [],
        targets: config.targets || [],
        budgets: config.contextBudget
      };
    }
    if (!config.controlPlane && (config.policies || config.mcp || config.evals)) {
      config.controlPlane = {
        policies: config.policies,
        mcp: config.mcp,
        evalGates: config.evals?.datasets ? [{ name: "default", strict: true }] : undefined
      };
    }

    if (config.compile) CompileConfigSchema.parse(config.compile);
    if (config.controlPlane) ControlPlaneConfigSchema.parse(config.controlPlane);

    return config;
  } catch (error) {
    if (error instanceof z.ZodError) {
      const issues = error.errors
        .map((err) => `- ${err.path.join(".")}: ${err.message}`)
        .join("\n");
      throw new ConfigLoadError(
        `Configuration validation failed in ${filePath}:\n${issues}`,
      );
    }
    throw new ConfigLoadError(`Unknown validation error in ${filePath}`);
  }
}

