import type { CapabilityManifest } from "./capabilities.js";

export class PolicyEngine {
  constructor(private policy: AgentPolicy) {}

  /**
   * Enforces NIST AI RMF and OWASP LLM controls dynamically
   */
  public validateExecution(
    toolName: string,
    capabilities: CapabilityManifest[],
    args: Record<string, any>,
  ): void {
    // 1. Basic tool existence & blocklist checks
    if (
      this.policy.deniedTools.includes(toolName) ||
      this.policy.deniedTools.includes("*")
    ) {
      throw new Error(
        `[LLM06: Excessive Agency] Policy Violation: Tool '${toolName}' is explicitly denied by policy '${this.policy.policyId}'.`,
      );
    }

    const capability = capabilities.find((c) => c.name === toolName);
    if (!capability) return;

    // 2. Autonomy Level boundary checks
    this.enforceAutonomyBoundaries(toolName, capability);

    // 3. Payload inspection for OWASP Top 10 Risks
    this.inspectPayload(toolName, args);
  }

  private enforceAutonomyBoundaries(
    toolName: string,
    capability: CapabilityManifest,
  ): void {
    const { autonomyLevel } = this.policy;
    const isWrite =
      capability.sideEffectLevel.includes("write") ||
      capability.sideEffectLevel.includes("submit");

    if (autonomyLevel === "observe" && isWrite) {
      throw new Error(
        `[LLM06: Excessive Agency] Policy Violation: Autonomy level 'observe' cannot execute write side-effect '${toolName}'.`,
      );
    }

    if (autonomyLevel === "advise") {
      if (
        capability.sideEffectLevel === "external-submit" ||
        capability.sideEffectLevel === "local-write" ||
        capability.sideEffectLevel === "external-write"
      ) {
        throw new Error(
          `[LLM06: Excessive Agency] Policy Violation: Autonomy level 'advise' cannot execute '${capability.sideEffectLevel}' tool '${toolName}'.`,
        );
      }
    }

    if (autonomyLevel === "act-with-approval" && capability.requiredApproval) {
      const allowedToApprove =
        this.policy.approvalRequiredFor.includes(toolName) ||
        this.policy.approvalRequiredFor.includes("*");
      if (!allowedToApprove) {
        throw new Error(
          `[LLM06: Excessive Agency] Policy Violation: Tool '${toolName}' requires approval, but policy '${this.policy.policyId}' does not whitelist it for approval-based execution.`,
        );
      }
    }
  }

  private inspectPayload(toolName: string, args: Record<string, any>): void {
    const payloadStr = JSON.stringify(args);

    // [LLM01: Prompt Injection] Heuristic payload scanning
    // A highly simplified mock of a WAF-like injection detector
    const injectionPatterns = [
      /ignore previous instructions/i,
      /system prompt/i,
      /you are now a/i,
      /<\|im_start\|>/i,
    ];
    for (const pattern of injectionPatterns) {
      if (pattern.test(payloadStr)) {
        throw new Error(
          `[LLM01: Prompt Injection] Policy Violation: Potential prompt injection payload detected in tool '${toolName}'. Execution halted.`,
        );
      }
    }

    // [LLM06: Sensitive Information Disclosure] PII Handling
    if (this.policy.piiHandling === "deny") {
      const piiPatterns = [
        /\b\d{3}-\d{2}-\d{4}\b/, // SSN format
        /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/, // Basic email
      ];
      for (const pattern of piiPatterns) {
        if (pattern.test(payloadStr)) {
          throw new Error(
            `[LLM06: Sensitive Information] Policy Violation: PII detected in payload for tool '${toolName}' while policy dictates 'deny'.`,
          );
        }
      }
    }
  }
}

export type AuditEventAction = "capability.invoke" | "policy.evaluate" | "approval.request" | "approval.consume" | "approval.expire" | "system.error" | "rate_limit.exceeded" | "auth.failed";
export type AuditEventDecision = "allow" | "deny" | "require_approval" | "error" | "pending" | "consumed" | "expired";
export type AuditRiskLevel = "low" | "medium" | "high" | "critical";

export interface AuditEvent {
  schemaVersion: "akcp.audit/v1";
  eventId: string;
  timestamp: string;
  requestId: string;
  actor: string;
  action: AuditEventAction;
  capabilityId?: string;
  decision: AuditEventDecision;
  riskLevel: AuditRiskLevel;
  evidence: {
    payloadHash?: string;
    policyIds?: string[];
    reason?: string;
    [key: string]: any;
  };
}

export interface IAuditLogService {
  logEvent(event: Omit<AuditEvent, "schemaVersion" | "eventId" | "timestamp">): Promise<string>;
  getEvents(limit?: number): Promise<AuditEvent[]>;
}

import fs from "fs";
import path from "path";
import crypto from "crypto";

export class InMemoryAuditLogService implements IAuditLogService {
  private events: AuditEvent[] = [];

  async logEvent(event: Omit<AuditEvent, "schemaVersion" | "eventId" | "timestamp">): Promise<string> {
    const id = `evt_${crypto.randomUUID().replace(/-/g, "")}`;
    const fullEvent: AuditEvent = {
      ...event,
      schemaVersion: "akcp.audit/v1",
      eventId: id,
      timestamp: new Date().toISOString()
    };
    this.events.push(fullEvent);
    return id;
  }

  async getEvents(limit: number = 100): Promise<AuditEvent[]> {
    return this.events.slice(-limit);
  }
}

export class FileAuditLogService implements IAuditLogService {
  private filePath: string;

  constructor(filePath: string) {
    this.filePath = filePath;
    const dir = path.dirname(this.filePath);
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true });
    }
  }

  async logEvent(event: Omit<AuditEvent, "schemaVersion" | "eventId" | "timestamp">): Promise<string> {
    const id = `evt_${crypto.randomUUID().replace(/-/g, "")}`;
    const fullEvent: AuditEvent = {
      ...event,
      schemaVersion: "akcp.audit/v1",
      eventId: id,
      timestamp: new Date().toISOString()
    };
    fs.appendFileSync(this.filePath, JSON.stringify(fullEvent) + "\n", "utf-8");
    return id;
  }

  async getEvents(limit: number = 100): Promise<AuditEvent[]> {
    if (!fs.existsSync(this.filePath)) {
      return [];
    }
    const lines = fs.readFileSync(this.filePath, "utf-8").split("\n").filter(l => l.trim().length > 0);
    const events = lines.map(l => JSON.parse(l) as AuditEvent);
    return events.slice(-limit);
  }
}

import path from "node:path";
import fs from "node:fs";
import * as yaml from "js-yaml";
import type { SourceAdapter, SourceImportReport } from "../connectors/types.js";
import { OpenWikiAdapter } from "../connectors/openwiki-adapter.js";
import { OkfAdapter } from "../connectors/okf-adapter.js";

export async function importSource(
  sourceType: "openwiki" | "okf",
  inputDir: string,
  outputDir: string,
  dryRun: boolean = false,
): Promise<SourceImportReport> {
  const adapter: SourceAdapter =
    sourceType === "openwiki" ? new OpenWikiAdapter() : new OkfAdapter();

  const report: SourceImportReport = {
    ok: true,
    sourceType,
    inputPath: inputDir,
    outputPath: outputDir,
    documentsFound: 0,
    documentsImported: 0,
    documentsSkipped: 0,
    diagnostics: [],
    provenance: [],
  };

  const detection = await adapter.detect(inputDir);
  if (!detection.isSupported) {
    report.ok = false;
    report.diagnostics.push({
      level: "error",
      message: `Input directory is not a valid ${sourceType} source. Reason: ${detection.reason}`,
    });
    return report;
  }

  const docs = await adapter.scan(inputDir);
  report.documentsFound = docs.length;

  for (const doc of docs) {
    try {
      const normalized = await adapter.normalize(doc);

      const relPath = path.relative(
        inputDir,
        doc.sourceUri.replace("file://", "").replace(/\\/g, "/"),
      );
      const targetPath = path.join(outputDir, relPath);

      report.provenance.push(normalized.provenance);

      if (!dryRun) {
        await fs.promises.mkdir(path.dirname(targetPath), { recursive: true });
        const finalYaml = yaml.dump(normalized.frontmatter);
        const finalContent = `---\n${finalYaml}---\n\n${normalized.markdown}`;
        await fs.promises.writeFile(targetPath, finalContent, "utf-8");
      }

      report.documentsImported++;
      report.diagnostics.push({
        level: "info",
        message: `Imported ${relPath} as ${normalized.type}`,
      });
    } catch (e: any) {
      report.documentsSkipped++;
      report.diagnostics.push({
        level: "error",
        message: `Failed to import ${doc.sourceUri}: ${e.message}`,
        uri: doc.sourceUri,
      });
    }
  }

  return report;
}

