export const tracer = api.trace.getTracer("akcp");

/**
 * Wraps an async function with an OpenTelemetry span and records duration.
 */
export async function withToolTracing<T>(
  toolName: string,
  toolVersion: string,
  requestId: string,
  fn: () => Promise<T>,
): Promise<{ data: T; durationMs: number }> {
  return tracer.startActiveSpan(`tool:${toolName}`, async (span) => {
    span.setAttribute("tool.name", toolName);
    span.setAttribute("tool.version", toolVersion);
    span.setAttribute("request.id", requestId);

    const start = performance.now();
    try {
      const data = await fn();
      const end = performance.now();
      const durationMs = end - start;
      mcpToolDurationHistogram.record(durationMs, { toolName });
      span.setAttribute("tool.duration_ms", durationMs);
      span.setStatus({ code: api.SpanStatusCode.OK });
      return { data, durationMs };
    } catch (err: any) {
      const end = performance.now();
      const durationMs = end - start;
      mcpToolDurationHistogram.record(durationMs, { toolName });
      span.setAttribute("tool.duration_ms", durationMs);
      span.recordException(err);
      span.setStatus({ code: api.SpanStatusCode.ERROR, message: err.message });
      throw err;
    } finally {
      span.end();
    }
  });
}

import { PluginManifestSchema } from "./manifest-schema.js";
import type { PluginManifest, PluginPermission } from "./manifest-schema.js";
import * as fs from "fs";
import * as path from "path";

export class PluginSecurityError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "PluginSecurityError";
  }
}

export class PluginValidationError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "PluginValidationError";
  }
}

export class PluginLoader {
  static loadManifest(pluginDir: string): PluginManifest {
    const manifestPath = path.join(pluginDir, "akcp-plugin.json");
    if (!fs.existsSync(manifestPath)) {
      throw new PluginValidationError(`Manifest not found at ${manifestPath}`);
    }

    try {
      const raw = fs.readFileSync(manifestPath, "utf-8");
      const data = JSON.parse(raw);
      return PluginManifestSchema.parse(data);
    } catch (err: any) {
      if (err.name === "ZodError") {
        throw new PluginValidationError(
          `Invalid manifest schema: ${err.message}`,
        );
      }
      throw new PluginValidationError(
        `Failed to parse manifest: ${err.message}`,
      );
    }
  }

  static async loadPlugin<T = any>(
    pluginDir: string,
    requiredPermissions: PluginPermission[] = [],
  ): Promise<{ manifest: PluginManifest; exports: T }> {
    const manifest = this.loadManifest(pluginDir);

    // Security Check: Verify declared permissions against required permissions
    for (const required of requiredPermissions) {
      if (!manifest.permissions.includes(required)) {
        throw new PluginSecurityError(
          `Plugin '${manifest.name}' requires undeclared permission: ${required}`,
        );
      }
    }

    // Attempt to load entrypoint
    const entrypointPath = path.join(pluginDir, manifest.entrypoint);
    if (!fs.existsSync(entrypointPath)) {
      throw new PluginValidationError(
        `Entrypoint not found at ${entrypointPath}`,
      );
    }

    try {
      // In a real isolated environment, this would be a secure sandbox or VM.
      // For build-time plugins we dynamically import, trusting the local workspace (with explicit permission checks as a guardrail).
      const pluginExports = await import(pathToFileURL(entrypointPath).href);
      return { manifest, exports: pluginExports };
    } catch (err: any) {
      throw new PluginValidationError(
        `Failed to load plugin entrypoint: ${err.message}`,
      );
    }
  }
}

import { pathToFileURL } from "url";

import * as fs from "fs";
import * as path from "path";
import { PluginLoader } from "./loader.js";
import type { PluginManifest } from "./manifest-schema.js";

export interface DiscoveredPlugin {
  dirPath: string;
  manifest: PluginManifest;
  error?: string;
}

export class PluginRegistry {
  /**
   * Discovers plugins in a given directory (e.g., ./plugins).
   * Scans subdirectories for `akcp-plugin.json` and validates them.
   */
  static discoverLocalPlugins(pluginsDir: string): DiscoveredPlugin[] {
    const discovered: DiscoveredPlugin[] = [];

    if (!fs.existsSync(pluginsDir)) {
      return discovered;
    }

    const entries = fs.readdirSync(pluginsDir, { withFileTypes: true });

    for (const entry of entries) {
      if (entry.isDirectory()) {
        const pluginDir = path.join(pluginsDir, entry.name);
        try {
          const manifest = PluginLoader.loadManifest(pluginDir);
          discovered.push({
            dirPath: pluginDir,
            manifest,
          });
        } catch (err: any) {
          // Record broken plugins so the CLI can report them instead of silently ignoring
          discovered.push({
            dirPath: pluginDir,
            manifest: null as any,
            error: err.message,
          });
        }
      }
    }

    return discovered;
  }
}

import fs from "node:fs";
import yaml from "yaml";
import { z } from "zod";
import { PolicyCardSchema } from "./schema.js";
import type { PolicyCard } from "./types.js";

export class PolicyLoadError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "PolicyLoadError";
  }
}

export function loadPolicy(filePath: string): PolicyCard {
  if (!fs.existsSync(filePath)) {
    throw new PolicyLoadError(`Policy file not found: ${filePath}`);
  }

  const fileContent = fs.readFileSync(filePath, "utf-8");

  let parsedYaml: any;
  try {
    parsedYaml = yaml.parse(fileContent);
  } catch (error: any) {
    throw new PolicyLoadError(
      `Failed to parse YAML file at ${filePath}:\n${error.message}`,
    );
  }

  try {
    return PolicyCardSchema.parse(parsedYaml);
  } catch (error) {
    if (error instanceof z.ZodError) {
      const issues = error.errors
        .map((err) => `- ${err.path.join(".")}: ${err.message}`)
        .join("\n");
      throw new PolicyLoadError(
        `Policy validation failed in ${filePath}:\n${issues}`,
      );
    }
    throw new PolicyLoadError(`Unknown validation error in ${filePath}`);
  }
}

import type { PiiRedactionResult } from "./pii-redactor.js";

/**
 * Client for interacting with external Security Gateways (e.g., Presidio, AWS Macie, Custom DLP engines).
 * Uses a standardized JSON REST payload.
 */
export class HttpSecurityGateway {
  private gatewayUrl: string;
  private tokenFormat: string;

  constructor(gatewayUrl: string, tokenFormat: string = "<REDACTED_{class}>") {
    this.gatewayUrl = gatewayUrl;
    this.tokenFormat = tokenFormat;
  }

  async redact(
    text: string,
    options: {
      mode: "redact" | "block";
      allowedClasses?: string[];
      blockedClasses?: string[];
      failOnUnredactedHighRiskPii?: boolean;
    }
  ): Promise<PiiRedactionResult> {
    try {
      const response = await fetch(this.gatewayUrl, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          text,
          mode: options.mode,
          allowedClasses: options.allowedClasses || [],
          blockedClasses: options.blockedClasses || [],
          tokenFormat: this.tokenFormat,
          failOnUnredactedHighRiskPii: options.failOnUnredactedHighRiskPii || false
        }),
      });

      if (!response.ok) {
        throw new Error(`Security Gateway returned ${response.status}: ${response.statusText}`);
      }

      const data = (await response.json()) as any;

      return {
        redactedText: data.redactedText || text,
        findings: data.findings || [],
        blocked: data.blocked || false,
      };
    } catch (err: any) {
      // If the gateway fails, fail closed if we are in block mode, or throw error.
      console.warn(`[WARN] Security Gateway call failed: ${err.message}`);
      throw new Error(`[PII_ERROR] Failed to reach Security Gateway at ${this.gatewayUrl}`);
    }
  }
}

export interface PiiMatch {
  type: string;       // "email", "cpf", "ssn", "phone", "credit_card", etc.
  value: string;      // o texto matched
  start: number;      // posição no texto
  end: number;
  confidence: "high" | "medium" | "low";
  locale?: string;    // "br", "us", etc.
}

export interface PiiDetector {
  detect(text: string): PiiMatch[] | Promise<PiiMatch[]>;
  supportedTypes(): string[];
}

export interface PiiDetectorConfig {
  locales?: string[];           // ["br", "us"] — quais locales ativar
  customPatterns?: PiiPattern[];  // patterns adicionais do usuário
  disabledTypes?: string[];     // tipos a ignorar
}

export interface PiiPattern {
  type: string;
  regex: RegExp;
  confidence: "high" | "medium" | "low";
  locale?: string;
}

export interface WAFResult {
  flagged: boolean;
  reason?: string;
  provider: "lakera" | "openai" | "regex-fallback";
}

export interface ISecurityGateway {
  checkPrompt(prompt: string): Promise<WAFResult>;
}

export class LakeraGateway implements ISecurityGateway {
  private apiKey: string | undefined;

  constructor() {
    this.apiKey = process.env.LAKERA_API_KEY;
  }

  async checkPrompt(prompt: string): Promise<WAFResult> {
    if (!this.apiKey) {
      console.warn("[WAF] LAKERA_API_KEY not set. Falling back to local Regex heuristic.");
      return this.regexFallback(prompt);
    }

    try {
      const response = await fetch("https://api.lakera.ai/v1/prompt_injection", {
        method: "POST",
        headers: {
          "Authorization": `Bearer ${this.apiKey}`,
          "Content-Type": "application/json"
        },
        body: JSON.stringify({ input: prompt })
      });

      if (!response.ok) {
        throw new Error(`Lakera API error: ${response.statusText}`);
      }

      const data = (await response.json()) as any;

      // Lakera typically returns a "flagged" boolean or "results[0].flagged" depending on the version.
      // Assuming a generic schema where `flagged: true` indicates malicious intent.
      const isFlagged = data.flagged || (data.results && data.results[0]?.flagged);

      return {
        flagged: !!isFlagged,
        reason: isFlagged ? "Lakera AI detected potential prompt injection" : undefined,
        provider: "lakera"
      };
    } catch (err: any) {
      console.error(`[WAF] Lakera API call failed (${err.message}). Falling back to local Regex.`);
      return this.regexFallback(prompt);
    }
  }

  private regexFallback(prompt: string): WAFResult {
    // Basic heuristics for SQLi / Prompt Injection / System prompt leaking
    const injectionPatterns = [
      /ignore all previous instructions/i,
      /you are now a/i,
      /system prompt/i,
      /drop table/i,
      /bypass/i
    ];

    for (const pattern of injectionPatterns) {
      if (pattern.test(prompt)) {
        return {
          flagged: true,
          reason: `Regex heuristics matched injection pattern: ${pattern}`,
          provider: "regex-fallback"
        };
      }
    }

    return {
      flagged: false,
      provider: "regex-fallback"
    };
  }
}

import crypto from "node:crypto";
import fs from "node:fs/promises";

/**
 * Generates a SHA-256 hash for a given string.
 */
export function hashString(data: string): string {
  return crypto.createHash("sha256").update(data).digest("hex");
}

/**
 * Generates a SHA-256 hash for a file.
 */
export async function hashFile(filePath: string): Promise<string> {
  const content = await fs.readFile(filePath);
  return crypto.createHash("sha256").update(content).digest("hex");
}

/**
 * Generates a stable SHA-256 hash for a config object, redacting specific keys (e.g. secrets)
 */
export function hashConfig(config: any): string {
  const redactedConfig = redactSecrets(config);
  // Stable stringify: sort keys so ordering doesn't break hash
  const stableString = stableStringify(redactedConfig);
  return hashString(stableString);
}

function redactSecrets(obj: any): any {
  if (obj === null || typeof obj !== "object") {
    return obj;
  }

  if (Array.isArray(obj)) {
    return obj.map(redactSecrets);
  }

  const result: any = {};
  for (const key of Object.keys(obj)) {
    const lowerKey = key.toLowerCase();
    if (
      lowerKey.includes("secret") ||
      lowerKey.includes("key") ||
      lowerKey.includes("token") ||
      lowerKey.includes("password")
    ) {
      result[key] = "[REDACTED]";
    } else {
      result[key] = redactSecrets(obj[key]);
    }
  }
  return result;
}

function stableStringify(obj: any): string {
  if (obj === null || typeof obj !== "object") {
    return JSON.stringify(obj);
  }
  if (Array.isArray(obj)) {
    return "[" + obj.map(stableStringify).join(",") + "]";
  }
  const sortedKeys = Object.keys(obj).sort();
  const pairs = sortedKeys.map(
    (k) => JSON.stringify(k) + ":" + stableStringify(obj[k]),
  );
  return "{" + pairs.join(",") + "}";
}

