import fs from "node:fs/promises";
import path from "node:path";
import { hashFile } from "./hash.js";
import type { BuildManifest } from "./types.js";

export interface VerifyReport {
  isValid: boolean;
  tamperedFiles: string[];
  missingFiles: string[];
  manifestTimestamp: string;
}

export async function verifyManifest(
  manifestPath: string,
): Promise<VerifyReport> {
  const fullManifestPath = path.resolve(process.cwd(), manifestPath);

  try {
    await fs.access(fullManifestPath);
  } catch {
    throw new Error(`Manifest not found at ${fullManifestPath}`);
  }

  const raw = await fs.readFile(fullManifestPath, "utf-8");
  let manifest: BuildManifest;
  try {
    manifest = JSON.parse(raw) as BuildManifest;
  } catch {
    throw new Error(`Failed to parse manifest JSON at ${fullManifestPath}`);
  }

  const report: VerifyReport = {
    isValid: true,
    tamperedFiles: [],
    missingFiles: [],
    manifestTimestamp: manifest.createdAt,
  };

  const basePath = process.cwd(); // Assume paths in manifest are relative to CWD

  for (const target of manifest.targets) {
    // Only verify hash if we have a single primary output matching the recorded hash
    if (target.outputs.length === 1 && typeof target.hash === "string") {
      const outputPath = target.outputs[0] as string;
      const fullTargetPath = path.resolve(basePath, outputPath);
      try {
        const currentHash = await hashFile(fullTargetPath);
        if (currentHash !== target.hash) {
          report.isValid = false;
          report.tamperedFiles.push(outputPath);
        }
      } catch (err: any) {
        if (err.code === "ENOENT") {
          report.isValid = false;
          report.missingFiles.push(outputPath);
        } else {
          throw err;
        }
      }
    } else {
      // Fallback: just check existence if no single hash is provided
      for (const outputPath of target.outputs) {
        const fullTargetPath = path.resolve(basePath, outputPath);
        try {
          await fs.access(fullTargetPath);
        } catch (err: any) {
          if (err.code === "ENOENT") {
            report.isValid = false;
            report.missingFiles.push(outputPath);
          } else {
            throw err;
          }
        }
      }
    }
  }

  return report;
}

import fs from "node:fs";
import path from "node:path";
import type { AkcpConfig } from "../config/akcp-config-schema.js";

export interface ReconcileOptions {
  dryRun: boolean;
}

export interface ReconcileResult {
  status: "in-sync" | "out-of-sync" | "error";
  differences: string[];
  message: string;
}

/**
 * Compares the desired state (akcp.yaml config) with the current state (filesystem).
 * For now, only supports dry-run (observability). Destructive changes will be implemented later.
 */
export async function reconcile(
  config: AkcpConfig,
  options: ReconcileOptions,
): Promise<ReconcileResult> {
  const differences: string[] = [];
  const fixesPerformed: string[] = [];

  // 1. Check sources existence
  const missingSources: string[] = [];
  for (const source of config.compile?.sources || []) {
    if (source.path) {
      const sourcePath = path.resolve(source.path);
      if (!fs.existsSync(sourcePath)) {
        if (options.dryRun) {
          differences.push(
            `Source missing: Directory '${source.path}' does not exist.`,
          );
        } else {
          missingSources.push(sourcePath);
        }
      }
    }
  }

  // 2. Check target output
  const missingTargets: any[] = [];
  if (config.compile?.targets) {
    for (const targetConf of config.compile?.targets) {
      const outPath = targetConf.out || targetConf.path || "";
      const targetPath = path.resolve(outPath);
      if (!fs.existsSync(targetPath)) {
        if (options.dryRun) {
          differences.push(
            `Target missing: Compiled output '${outPath}' does not exist.`,
          );
        } else {
          missingTargets.push(targetConf);
        }
      }
    }
  }

  // 3. Dry run semantics
  if (options.dryRun) {
    if (differences.length === 0) {
      return {
        status: "in-sync",
        differences,
        message: "Dry run: System is in-sync with desired state.",
      };
    } else {
      return {
        status: "out-of-sync",
        differences,
        message:
          "Dry run: System is out-of-sync. Re-compilation or environment fixes required.",
      };
    }
  }

  // 4. Mutation logic (dryRun = false)
  // Create missing source directories
  for (const sourcePath of missingSources) {
    fs.mkdirSync(sourcePath, { recursive: true });
    fixesPerformed.push(
      `Created missing source directory: '${path.relative(process.cwd(), sourcePath)}'`,
    );
  }

  // Compile missing targets
  if (missingTargets.length > 0) {
    const { buildKnowledgeIR } = await import("../ir/build-ir.js");
    const { IrJsonTarget } = await import("../targets/ir-json.js");
    const { OkfBundleTarget } = await import("../targets/okf-bundle.js");
    const { OpenWikiDocsTarget } = await import("../targets/openwiki-docs.js");
    const { AgentsMdTarget } = await import("../targets/agents-md.js");
    const { McpResourcesManifestTarget } =
      await import("../targets/mcp-resources-manifest.js");
    const { PolicyBundleTarget } = await import("../targets/policy-bundle.js");
    const { EvalDatasetTarget } = await import("../targets/eval-dataset.js");
    const { GraphJsonTarget } = await import("../targets/graph-json.js");
    const { ProvenanceManifestBuilder } =
      await import("../provenance/build-manifest.js");

    const bundleRoot = path.resolve(".");
    const ir = await buildKnowledgeIR(bundleRoot, {
      sources: config.compile?.sources,
    });
    const manifestBuilder = new ProvenanceManifestBuilder();

    const targetInstances: Record<string, any> = {
      "ir-json": new IrJsonTarget(),
      "okf-bundle": new OkfBundleTarget(),
      "openwiki-docs": new OpenWikiDocsTarget(),
      "agents-md": new AgentsMdTarget(),
      "mcp-resources-manifest": new McpResourcesManifestTarget(),
      "policy-bundle": new PolicyBundleTarget(),
      "eval-dataset": new EvalDatasetTarget(),
      "graph-json": new GraphJsonTarget(),
    };

    for (const targetConf of missingTargets) {
      const targetImpl = targetInstances[targetConf.type];
      if (targetImpl) {
        const outPath = path.resolve(targetConf.out || targetConf.path || "");
        fs.mkdirSync(path.dirname(outPath), { recursive: true });
        const output = await targetImpl.compile(ir, targetConf);
        manifestBuilder.addOutput(output);
        fixesPerformed.push(
          `Compiled missing target: '${targetConf.type}' -> '${targetConf.out || targetConf.path}'`,
        );
      }
    }

    // Write build manifest
    await manifestBuilder.writeManifest(
      ir,
      "dist/akcp-manifest.json",
      "none",
      "0.1.0",
    );
  }

  if (fixesPerformed.length === 0) {
    return {
      status: "in-sync",
      differences: [],
      message: "System is already in-sync. No fixes needed.",
    };
  } else {
    return {
      status: "in-sync",
      differences: [],
      message: `Reconciliation complete. Fixed issues:\n${fixesPerformed.map((f) => `  - ${f}`).join("\n")}`,
    };
  }
}

import { ScorecardDimension } from "./types.js";
import type { ScorecardReport, DimensionScore } from "./types.js";
import { generateRecommendations } from "./recommendations.js";
import type { AgentKnowledgeIR } from "../ir/types.js";

export function calculateScorecard(
  ir: AgentKnowledgeIR,
  rawFiles: { path: string; content: string }[] = [],
): ScorecardReport {
  const dimensions: DimensionScore[] = [];

  // 1. Knowledge Structure (10 pts)
  // E.g. Check if concepts have semantic subdirectories
  let structureScore = 0;
  if (ir.concepts.length > 0) {
    const rootFiles = ir.concepts.filter(
      (c) =>
        !c.source.filePath.includes("/") && !c.source.filePath.includes("\\"),
    );
    const nonRootRatio = 1 - rootFiles.length / ir.concepts.length;
    structureScore = Math.round(nonRootRatio * 10);
  }
  dimensions.push({
    dimension: ScorecardDimension.KnowledgeStructure,
    score: structureScore,
    maxScore: 10,
    details: [
      `Found ${ir.concepts.length} concepts, with ${structureScore}0% in subdirectories.`,
    ],
  });

  // 2. OKF Compatibility (10 pts)
  let okfScore = 0;
  if (ir.concepts.length > 0) {
    const validOkf = ir.concepts.filter(
      (c) => c.frontmatter && c.frontmatter.type,
    );
    okfScore = Math.round((validOkf.length / ir.concepts.length) * 10);
  }
  dimensions.push({
    dimension: ScorecardDimension.OKFCompatibility,
    score: okfScore,
    maxScore: 10,
    details: [`${okfScore}0% of documents have valid type frontmatter.`],
  });

  // 3. Context Economy (10 pts)
  let economyScore = 0;
  if (ir.concepts.length > 0) {
    const totalTokens = ir.concepts.reduce(
      (sum, c) => sum + (c.budget?.estimatedTokens || 0),
      0,
    );
    const avgTokens = totalTokens / ir.concepts.length;
    // Penalty if average > 2000
    if (avgTokens < 500) economyScore = 10;
    else if (avgTokens < 1000) economyScore = 8;
    else if (avgTokens < 2000) economyScore = 5;
    else economyScore = 2;
  }
  dimensions.push({
    dimension: ScorecardDimension.ContextEconomy,
    score: economyScore,
    maxScore: 10,
    details: [`Average concept token size is within acceptable limits.`],
  });

  // 4. MCP Readiness (10 pts)
  let mcpScore = 0;
  const hasMcpTarget = ir.targets?.some(
    (t: any) =>
      t === "mcp-profile-server" ||
      t === "mcp-automation-server" ||
      t?.type?.includes("mcp"),
  );
  if (hasMcpTarget) mcpScore = 10;
  dimensions.push({
    dimension: ScorecardDimension.MCPReadiness,
    score: mcpScore,
    maxScore: 10,
    details: hasMcpTarget
      ? ["MCP target detected in compile configuration."]
      : ["No MCP targets detected."],
  });

  // 5. Policy Coverage (10 pts)
  let policyScore = 0;
  if (ir.policies && Object.keys(ir.policies).length > 0) {
    policyScore = 10;
  }
  dimensions.push({
    dimension: ScorecardDimension.PolicyCoverage,
    score: policyScore,
    maxScore: 10,
    details:
      policyScore === 10
        ? ["Policies object is populated."]
        : ["No policies detected."],
  });

  // 6. Security Posture (10 pts)
  let securityScore = 0;
  if (
    ir.policies?.defaultAutonomyLevel ||
    ir.policies?.piiHandling ||
    ir.policies?.disableDangerousTools !== undefined
  ) {
    securityScore = 10;
  }
  dimensions.push({
    dimension: ScorecardDimension.SecurityPosture,
    score: securityScore,
    maxScore: 10,
    details:
      securityScore === 10
        ? ["Security policy constraints found."]
        : ["Missing explicit security constraints."],
  });

  // 7. Provenance (10 pts)
  let provenanceScore = 0;
  if (
    ir.concepts.length > 0 &&
    ir.concepts.some((c) => c.provenance?.sourceHash)
  ) {
    provenanceScore = 10;
  }
  dimensions.push({
    dimension: ScorecardDimension.Provenance,
    score: provenanceScore,
    maxScore: 10,
    details:
      provenanceScore === 10
        ? ["Provenance hashes generated."]
        : ["Provenance generation is disabled."],
  });

  // 8. Evals (10 pts)
  let evalsScore = 0;
  const hasEvalTargets = ir.targets?.some(
    (t: any) => t === "eval-dataset" || t?.type === "eval-dataset",
  );
  const hasTestFiles = rawFiles.some(
    (f) =>
      f.path.includes(".test.ts") ||
      f.path.includes("__tests__") ||
      f.path.includes("evals/"),
  );
  if (hasEvalTargets || hasTestFiles) {
    evalsScore = 10;
  }
  dimensions.push({
    dimension: ScorecardDimension.Evals,
    score: evalsScore,
    maxScore: 10,
    details:
      evalsScore === 10
        ? ["Evaluation configurations/files found."]
        : ["No evaluation integration detected."],
  });

  // 9. Freshness (10 pts)
  let freshnessScore = 0;
  if (ir.concepts.length > 0) {
    const staleCount = ir.concepts.filter((c) => c.isStale).length;
    const staleRatio = staleCount / ir.concepts.length;
    if (staleRatio === 0) freshnessScore = 10;
    else if (staleRatio < 0.1) freshnessScore = 8;
    else if (staleRatio < 0.3) freshnessScore = 5;
    else freshnessScore = 2;
  }
  dimensions.push({
    dimension: ScorecardDimension.Freshness,
    score: freshnessScore,
    maxScore: 10,
    details: [
      `Bundle has ${ir.concepts.filter((c) => c.isStale).length} stale concepts.`,
    ],
  });

  // 10. DX (10 pts)
  let dxScore = 0;
  const hasIndex = rawFiles.some(
    (f) => f.path === "index.md" || f.path === "index.yaml",
  );
  const hasLog = rawFiles.some((f) => f.path === "log.md");
  if (hasIndex) dxScore += 5;
  if (hasLog) dxScore += 5;
  dimensions.push({
    dimension: ScorecardDimension.DX,
    score: dxScore,
    maxScore: 10,
    details: [`Index present: ${hasIndex}, Log present: ${hasLog}.`],
  });

  const totalScore = dimensions.reduce((sum, dim) => sum + dim.score, 0);

  return {
    totalScore,
    maxTotalScore: 100,
    dimensions,
    recommendations: generateRecommendations(dimensions),
    timestamp: new Date().toISOString(),
    bundleId: ir.bundleId,
  };
}

export enum ScorecardDimension {
  KnowledgeStructure = "knowledge-structure",
  OKFCompatibility = "okf-compatibility",
  ContextEconomy = "context-economy",
  MCPReadiness = "mcp-readiness",
  PolicyCoverage = "policy-coverage",
  SecurityPosture = "security-posture",
  Provenance = "provenance",
  Evals = "evals",
  Freshness = "freshness",
  DX = "dx",
}

export interface DimensionScore {
  dimension: ScorecardDimension;
  score: number;
  maxScore: number;
  details: string[];
}

export interface Recommendation {
  dimension: ScorecardDimension;
  action: string;
  impact: "high" | "medium" | "low";
}

export interface ScorecardReport {
  totalScore: number;
  maxTotalScore: number;
  dimensions: DimensionScore[];
  recommendations: Recommendation[];
  timestamp: string;
  bundleId: string;
}

/**
 * @module services/okf-document-service
 * @description High-level orchestration service for OKF document operations.
 *
 * Coordinates the {@link IOKFRepository}, {@link IIndexService}, and
 * {@link ILogService} to provide complete document lifecycle management.
 * Every mutation (create, update, delete) triggers index regeneration
 * and a log entry so the bundle remains self-documenting.
 */

import path from "node:path";

import type {
  IIndexService,
  ILogService,
  IOKFRepository,
} from "../domain/interfaces.js";
import type {
  CareerContext,
  OKFDocument,
  OKFFrontmatter,
} from "../domain/types.js";
import { OKFDocumentType } from "../domain/types.js";

/**
 * Orchestrates document CRUD, index regeneration, and change logging.
 *
 * @example
 * ```ts
 * const service = new OKFDocumentService(repo, indexService, logService, '/career-bundle');
 * await service.createDocument(
 *   { type: 'Skill', title: 'TypeScript' },
 *   '## Details\nStrong experience with TypeScript.',
 *   'skills/typescript',
 * );
 * ```
 */
export class OKFDocumentService {
  private readonly repository: IOKFRepository;
  private readonly indexService: IIndexService;
  private readonly logService: ILogService;
  private readonly bundleRoot: string;

  /**
   * @param repository   - OKF document repository for persistence
   * @param indexService - Service for regenerating `index.md` files
   * @param logService   - Service for appending to `log.md`
   * @param bundleRoot   - Absolute path to the OKF bundle root directory
   */
  constructor(
    repository: IOKFRepository,
    indexService: IIndexService,
    logService: ILogService,
    bundleRoot: string,
  ) {
    this.repository = repository;
    this.indexService = indexService;
    this.logService = logService;
    this.bundleRoot = bundleRoot;
  }

  /**
   * Get the root path of the bundle.
   */
  get bundleRootPath(): string {
    return this.bundleRoot;
  }

  /**
   * Create a new OKF document.
   *
   * Saves the document via the repository, regenerates the parent
   * directory's `index.md`, and records the creation in `log.md`.
   *
   * Supports calling with a single OKFDocument object or separate arguments.
   *
   * @param frontmatterOrDoc - YAML frontmatter for the new document, or the full OKFDocument object
   * @param body             - Markdown body content (required if first argument is frontmatter)
   * @param conceptId        - Concept ID (e.g. `skills/typescript`, required if first argument is frontmatter)
   */
  async createDocument(
    frontmatterOrDoc: OKFFrontmatter | OKFDocument,
    body?: string,
    conceptId?: string,
  ): Promise<void> {
    let document: OKFDocument;

    if (this.isOKFDocument(frontmatterOrDoc)) {
      document = { ...frontmatterOrDoc };
      if (!document.filePath) {
        document.filePath = path.join(
          this.bundleRoot,
          `${document.conceptId}.md`,
        );
      }
    } else {
      if (body === undefined || conceptId === undefined) {
        throw new Error(
          "body and conceptId are required when passing frontmatter separately",
        );
      }
      const filePath = path.join(this.bundleRoot, `${conceptId}.md`);
      document = {
        frontmatter: frontmatterOrDoc,
        body,
        filePath,
        conceptId,
      };
    }

    await this.repository.save(document);

    // Regenerate the parent directory's index
    const parentDir = path.dirname(document.filePath);
    await this.indexService.generate(parentDir);

    // Log the creation
    await this.logService.append({
      timestamp: new Date().toISOString(),
      action: "created",
      conceptId: document.conceptId,
      details: `Created document: ${document.frontmatter.title ?? document.conceptId}`,
    });
  }

  /**
   * Update an existing OKF document.
   *
   * Finds the document by concept ID, merges the frontmatter updates,
   * optionally replaces the body, saves, and logs the update.
   *
   * Supports calling with a full OKFDocument object directly.
   *
   * @param conceptIdOrDoc - Concept ID of the document to update, or the updated OKFDocument object
   * @param updates        - Partial frontmatter fields to merge (ignored if first argument is OKFDocument)
   * @param bodyUpdate     - Optional new body content (replaces existing if provided)
   * @returns The updated document
   * @throws {OKFFileNotFoundError} When no document exists for the given concept ID
   */
  async updateDocument(
    conceptIdOrDoc: string | OKFDocument,
    updates?: Partial<OKFFrontmatter>,
    bodyUpdate?: string,
  ): Promise<OKFDocument> {
    let conceptId: string;
    let frontmatterUpdates: Partial<OKFFrontmatter>;
    let newBody: string | undefined;

    if (typeof conceptIdOrDoc === "string") {
      conceptId = conceptIdOrDoc;
      frontmatterUpdates = updates ?? {};
      newBody = bodyUpdate;
    } else {
      conceptId = conceptIdOrDoc.conceptId;
      frontmatterUpdates = conceptIdOrDoc.frontmatter;
      newBody = conceptIdOrDoc.body;
    }

    const existing = await this.repository.findById(conceptId);

    if (!existing) {
      // Import dynamically to avoid circular issues (the error is lightweight)
      const { OKFFileNotFoundError } = await import("../domain/errors.js");
      const filePath = path.join(this.bundleRoot, `${conceptId}.md`);
      throw new OKFFileNotFoundError(filePath);
    }

    // Merge frontmatter updates
    const mergedFrontmatter: OKFFrontmatter =
      typeof conceptIdOrDoc === "string"
        ? {
            ...existing.frontmatter,
            ...frontmatterUpdates,
            timestamp: new Date().toISOString(),
          }
        : {
            ...frontmatterUpdates,
            type: existing.frontmatter.type,
            timestamp: new Date().toISOString(),
          };

    const updatedDocument: OKFDocument = {
      frontmatter: mergedFrontmatter,
      body: newBody !== undefined ? newBody : existing.body,
      filePath: existing.filePath,
      conceptId: existing.conceptId,
    };

    await this.repository.save(updatedDocument);

    // Log the update
    const updatedFields =
      typeof conceptIdOrDoc === "string"
        ? Object.keys(frontmatterUpdates)
        : Object.keys(updates ?? {});

    await this.logService.append({
      timestamp: new Date().toISOString(),
      action: "updated",
      conceptId,
      details: `Updated fields: ${updatedFields.join(", ")}`,
    });

    return updatedDocument;
  }

  /**
   * Delete an OKF document by its concept ID.
   *
   * Removes the file via the repository, regenerates the parent
   * directory's `index.md`, and records the deletion in `log.md`.
   *
   * @param conceptId - Concept ID of the document to delete
   * @throws {OKFFileNotFoundError} When no document exists for the given concept ID
   */
  async deleteDocument(conceptId: string): Promise<void> {
    const filePath = path.join(this.bundleRoot, `${conceptId}.md`);

    await this.repository.delete(conceptId);

    // Regenerate the parent directory's index
    const parentDir = path.dirname(filePath);
    await this.indexService.generate(parentDir);

    // Log the deletion
    await this.logService.append({
      timestamp: new Date().toISOString(),
      action: "deleted",
      conceptId,
      details: `Deleted document: ${conceptId}`,
    });
  }

  /**
   * Aggregate all documents grouped by type into a {@link CareerContext}.
   *
   * Used by the MCP `read_career_context` tool to provide a comprehensive
   * snapshot of the user's professional profile to LLMs.
   *
   * @returns A {@link CareerContext} object with documents grouped by type
   */
  async getCareerContext(): Promise<CareerContext> {
    const [
      skills,
      experiences,
      education,
      certificates,
      projects,
      preferences,
      applications,
    ] = await Promise.all([
      this.repository.findByType(OKFDocumentType.Skill),
      this.repository.findByType(OKFDocumentType.Experience),
      this.repository.findByType(OKFDocumentType.Education),
      this.repository.findByType(OKFDocumentType.Certificate),
      this.repository.findByType(OKFDocumentType.Project),
      this.repository.findByType(OKFDocumentType.Preference),
      this.repository.findByType(OKFDocumentType.Application),
    ]);

    return {
      skills,
      experiences,
      education,
      certificates,
      projects,
      preferences,
      applications,
    };
  }

  /**
   * Retrieve a single document by concept ID.
   *
   * Delegates directly to the repository's {@link IOKFRepository.findById}.
   *
   * @param conceptId - Concept ID to look up
   * @returns The parsed document, or `null` if not found
   */
  async getDocument(conceptId: string): Promise<OKFDocument | null> {
    return this.repository.findById(conceptId);
  }

  /**
   * Type guard to check if an object implements {@link OKFDocument}.
   */
  private isOKFDocument(obj: any): obj is OKFDocument {
    return (
      obj &&
      typeof obj === "object" &&
      "frontmatter" in obj &&
      "body" in obj &&
      "conceptId" in obj
    );
  }
}

import fs from "node:fs/promises";
import path from "node:path";
import { createHash } from "node:crypto";
import type { CompileTarget, TargetConfig, TargetOutput } from "./types.js";
import type { AgentKnowledgeIR } from "../ir/types.js";
import { FrontmatterParser } from "../infrastructure/frontmatter-parser.js";

export class OpenWikiDocsTarget implements CompileTarget {
  public readonly targetType = "openwiki";

  async compile(
    ir: AgentKnowledgeIR,
    config: TargetConfig,
  ): Promise<TargetOutput> {
    const outDir = path.resolve(process.cwd(), config.out);

    await fs.mkdir(outDir, { recursive: true });

    let totalBytes = 0;
    const hash = createHash("sha256");
    const parser = new FrontmatterParser();

    // Generate an index.md
    let indexContent = `# Context Knowledge\n\nGenerated automatically from AKCP Compiler.\n\n`;

    for (const concept of ir.concepts) {
      const fileName = `${concept.conceptId.replace(/[\\/]/g, "-")}.md`;
      const filePath = path.join(outDir, fileName);

      // Restore frontmatter to ensure OpenWiki interoperability
      const frontmatter = concept.frontmatter || { type: concept.type || "Document" };
      const bodyWithHeading = `# ${concept.conceptId}\n\n${concept.body}`;

      const content = parser.serialize(frontmatter as any, bodyWithHeading);

      await fs.writeFile(filePath, content, "utf-8");

      hash.update(content);
      totalBytes += Buffer.byteLength(content, "utf8");

      indexContent += `- [${concept.conceptId}](./${fileName})\n`;
    }

    const indexPath = path.join(outDir, "index.md");
    await fs.writeFile(indexPath, indexContent, "utf-8");
    hash.update(indexContent);
    totalBytes += Buffer.byteLength(indexContent, "utf8");

    // Generate OpenWiki metadata manifest
    const metadata = {
      generatedAt: ir.timestamp || new Date().toISOString(),
      targetType: this.targetType,
      bundleId: ir.bundleId,
      sourceHashes: ir.sourceHashes || {},
      compilerVersion: "AKCP-v1"
    };

    const metadataPath = path.join(outDir, ".akcp-openwiki-metadata.json");
    const metadataContent = JSON.stringify(metadata, null, 2);
    await fs.writeFile(metadataPath, metadataContent, "utf-8");
    hash.update(metadataContent);
    totalBytes += Buffer.byteLength(metadataContent, "utf8");

    return {
      targetType: this.targetType,
      outputPath: outDir,
      hash: hash.digest("hex"),
      bytesWritten: totalBytes,
    };
  }
}

