/**
 * @module automation/interfaces
 * @description Strategy pattern contracts for multi-platform browser application automation.
 */

import type { Page } from "playwright";
import type { CareerContext } from "@akcp/core";

/**
 * Result of a browser automation attempt.
 */
export interface ApplicationResult {
  /** Whether the application was successfully submitted. */
  success: boolean;
  /** The platform target (e.g. 'LinkedIn', 'Gupy', 'Indeed'). */
  platform: string;
  /** Position title extracted or applied to. */
  jobTitle: string;
  /** Company name extracted or applied to. */
  company: string;
  /** ISO 8601 timestamp of execution. */
  submittedAt: string;
  /** Any error details if the submission failed. */
  errors?: string[];
}

/**
 * Strategy interface for platform-specific job application workflows.
 * Implementing classes must handle specific platforms (LinkedIn, Gupy, Indeed).
 */
export interface IApplicationStrategy {
  /**
   * Identifies if the URL is supported by this strategy.
   *
   * @param url - The job application URL
   * @returns true if the strategy can process this URL, false otherwise
   */
  supports(url: string): boolean;

  /**
   * Automate application submission on the target page.
   *
   * This is a scaffold. Per security restrictions, it uses POM classes
   * and logs progress, but does not perform real form submission using real credentials.
   *
   * @param page - Playwright page object representing the current browser tab
   * @param careerContext - The parsed OKF career bundle containing candidate context
   * @param url - The job listing URL
   * @param dryRun - Whether to run without submitting
   * @returns The outcome of the application attempt
   * @throws {AutomationError} If any locator or step fails
   */
  apply(
    page: Page,
    careerContext: CareerContext,
    url: string,
    dryRun?: boolean,
  ): Promise<ApplicationResult>;
}

/**
 * @module index
 * @description Entrypoint for the MCP Automation Server.
 */

import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import path from "node:path";
import {
  FileSystemAdapter,
  FrontmatterParser,
  OKFFileRepository,
  OKFCachedRepository,
  IndexService,
  LogService,
  OKFDocumentService,
  startTelemetry,
} from "@akcp/core";
import { AKCPAutomationServer } from "./server.js";
import fs from "node:fs";

async function main() {
  try {
    // Start telemetry NodeSDK
    startTelemetry();

    const bundleRootEnv =
      process.env["AKCP_BUNDLE_PATH"] || process.env["AKCP_BUNDLE_PATH"];
    if (process.env["AKCP_BUNDLE_PATH"] && !process.env["AKCP_BUNDLE_PATH"]) {
      console.warn(
        "[WARNING] AKCP_BUNDLE_PATH is deprecated. Please use AKCP_BUNDLE_PATH.",
      );
    }
    const bundleRoot = path.resolve(bundleRootEnv || "./.okf");

    const irPathEnv = process.env["AKCP_IR_PATH"] || process.env["AKCP_IR_PATH"];
    if (process.env["AKCP_IR_PATH"] && !process.env["AKCP_IR_PATH"]) {
      console.warn(
        "[WARNING] AKCP_IR_PATH is deprecated. Please use AKCP_IR_PATH.",
      );
    }
    const irPath = path.resolve(irPathEnv || "./dist/knowledge-ir.json");

    console.error(
      `[AKCP Automation Server] Initializing bundle at: ${bundleRoot}`,
    );

    const fsAdapter = new FileSystemAdapter();
    const fmParser = new FrontmatterParser();

    await fsAdapter.mkdir(bundleRoot);
    let repo: any = new OKFFileRepository(fsAdapter, fmParser, bundleRoot);

    if (fs.existsSync(irPath)) {
      console.error(
        `[AKCP Automation Server] Found Knowledge IR at ${irPath}. Enabling in-memory cache.`,
      );
      try {
        const irContent = fs.readFileSync(irPath, "utf-8");
        const ir = JSON.parse(irContent);
        repo = new OKFCachedRepository(repo, ir);
      } catch (err: any) {
        console.error(
          `[AKCP Automation Server] Failed to load IR, falling back to disk-only: ${err.message}`,
        );
      }
    } else {
      console.error(
        `[AKCP Automation Server] No Knowledge IR found. Running in disk-only mode.`,
      );
    }

    const indexService = new IndexService(fsAdapter, fmParser, bundleRoot);
    const logService = new LogService(
      fsAdapter,
      path.join(bundleRoot, "log.md"),
    );
    const docService = new OKFDocumentService(
      repo,
      indexService,
      logService,
      bundleRoot,
    );

    const mcpAutomationServer = new AKCPAutomationServer(docService);
    const serverInstance = mcpAutomationServer.getServerInstance();

    const transport = new StdioServerTransport();
    await serverInstance.connect(transport);

    console.error(
      "[AKCP Automation Server] Successfully connected via stdio transport.",
    );
  } catch (error) {
    console.error("[AKCP Automation Server] Fatal startup error:", error);
    process.exit(1);
  }
}

main().catch((err) => {
  console.error("[AKCP Automation Server] Unhandled rejection:", err);
  process.exit(1);
});

/**
 * @module server
 * @description Configures tools for the MCP Automation Server with stateful HITL gates.
 */

import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { z } from "zod";
import crypto from "node:crypto";
import {
  OKFDocumentService,
  OKFDocumentFactory,
  ApplicationStatus,
  mcpToolCallsCounter,
  mcpToolFailuresCounter,
  automationAttemptsCounter,
  automationApprovalRequiredCounter,
  automationSubmissionSuccessCounter,
  createToolSuccess,
  createToolFailure,
  withToolTracing,
  MCPGateway,
  type GatewayConfig,
} from "@akcp/core";
import { BrowserOrchestrator } from "./automation/browser-orchestrator.js";
import { ApprovalStore } from "./approval/approval-store.js";
import { RedisApprovalStore } from "./approval/redis-store.js";
import { auditLogger } from "./audit/audit-log.js";
import { automationServerCapabilities } from "./capabilities.js";
import type { IApprovalStore } from "./approval/types.js";

const approvalStore: IApprovalStore = process.env.REDIS_URL
  ? new RedisApprovalStore()
  : new ApprovalStore();

// Centralized approval store handles pending tokens

export class AKCPAutomationServer {
  private readonly server: McpServer;
  private readonly docService: OKFDocumentService;
  private readonly orchestrator: BrowserOrchestrator;
  private readonly gateway: MCPGateway;

  constructor(
    docService: OKFDocumentService,
    gatewayConfig: GatewayConfig = { policies: {} },
  ) {
    this.docService = docService;
    this.orchestrator = new BrowserOrchestrator();
    this.gateway = new MCPGateway({ ...gatewayConfig, approvalStore });

    // Create the MCP server instance
    this.server = new McpServer({
      name: "akcp-automation-server",
      version: "0.1.0",
    });

    this.registerTools();
  }

  getServerInstance(): McpServer {
    return this.server;
  }

  private registerTools(): void {
    // Tool: preview_application
    this.server.tool(
      "preview_application",
      automationServerCapabilities.find((c) => c.name === "preview_application")
        ?.description || "",
      {
        jobUrl: z
          .string()
          .url()
          .describe("The job posting vacancy URL to preview"),
        _agentId: z.string().optional().describe("Agent Identity"),
        _approvalToken: z
          .string()
          .optional()
          .describe("Approval token for human-in-the-loop"),
      },
      async ({ jobUrl, _agentId, _approvalToken }) => {
        const reqId = crypto.randomUUID();
        const toolName = "preview_application";
        const toolVersion = "0.1.0";
        mcpToolCallsCounter.add(1);

        try {
          const { data, durationMs } = await this.gateway.execute(
            {
              requestId: reqId,
              toolName,
              sideEffect: "read",
              agentId: _agentId,
              payload: { jobUrl, _approvalToken },
            },
            async () => {
              return await withToolTracing(
                toolName,
                toolVersion,
                reqId,
                async () => {
                  const platform = this.detectPlatform(jobUrl);
                  return {
                    jobUrl,
                    platform,
                    requiredFields: [
                      "first_name",
                      "last_name",
                      "email",
                      "resume_file",
                      "phone",
                    ],
                    estimatedAutonomyLevel: "act-with-approval",
                  };
                },
              );
            },
          );

          return {
            content: [
              {
                type: "text",
                text: JSON.stringify(
                  createToolSuccess(data, {
                    requestId: reqId,
                    toolName,
                    toolVersion,
                    durationMs,
                  }),
                  null,
                  2,
                ),
              },
            ],
          };
        } catch (err: any) {
          mcpToolFailuresCounter.add(1);
          const errorCode =
            err.name === "MCPGatewayError" ? err.code : "PREVIEW_ERROR";
          return {
            isError: true,
            content: [
              {
                type: "text",
                text: JSON.stringify(
                  createToolFailure(
                    err.message,
                    errorCode,
                    { requestId: reqId, toolName, toolVersion, durationMs: 0 },
                    { approvalToken: err.data?.approvalToken },
                  ),
                  null,
                  2,
                ),
              },
            ],
          };
        }
      },
    );

    // Tool: prepare_application
    this.server.tool(
      "prepare_application",
      automationServerCapabilities.find((c) => c.name === "prepare_application")
        ?.description || "",
      {
        jobUrl: z.string().url().describe("The target job posting vacancy URL"),
        _agentId: z.string().optional().describe("Agent Identity"),
      },
      async ({ jobUrl, _agentId }) => {
        const reqId = crypto.randomUUID();
        const toolName = "prepare_application";
        const toolVersion = "0.1.0";
        mcpToolCallsCounter.add(1);
        automationAttemptsCounter.add(1);
        automationApprovalRequiredCounter.add(1);

        try {
          const { data, durationMs } = await this.gateway.execute(
            {
              requestId: reqId,
              toolName,
              sideEffect: "read",
              agentId: _agentId,
              payload: { jobUrl },
            },
            async () => {
              return await withToolTracing(
                toolName,
                toolVersion,
                reqId,
                async () => {
                  const context = await this.docService.getCareerContext();

                  const pref = context.preferences[0];
                  const roles = pref?.frontmatter["roles"] || [];

                  const preparedFields = {
                    rolesApplied: Array.isArray(roles)
                      ? roles.join(", ")
                      : "Software Engineer",
                    status: "Draft",
                  };

                  const payload = { jobUrl, context, preparedFields };
                  const metadata = {
                    jobUrl,
                    platform: this.detectPlatform(jobUrl),
                  };
                  const payloadHash = crypto.createHash("sha256").update(JSON.stringify(payload)).digest("hex");
                  const token = await approvalStore.generateToken(
                    reqId,
                    "confirm_application_submission",
                    payloadHash,
                    "high",
                    "write",
                    _agentId || "anonymous",
                    metadata,
                  );

                  return { token, preparedFields };
                },
              );
            },
          );

          auditLogger.log({
            requestId: data.token,
            toolName: "prepare_application",
            autonomyLevel: "act-with-approval",
            approvalRequired: false,
            sideEffectLevel: "external-read",
            status: "success",
            durationMs,
          });

          return {
            content: [
              {
                type: "text",
                text: JSON.stringify(
                  createToolSuccess(
                    {
                      message:
                        "Application pre-filled and locked. Explicit human authorization is required to submit.",
                      approvalToken: data.token,
                      autonomyLevel: "act-with-approval",
                      preparedFields: data.preparedFields,
                    },
                    { requestId: reqId, toolName, toolVersion, durationMs },
                  ),
                  null,
                  2,
                ),
              },
            ],
          };
        } catch (err: any) {
          mcpToolFailuresCounter.add(1);
          auditLogger.log({
            requestId: reqId,
            toolName: "prepare_application",
            autonomyLevel: "advise",
            approvalRequired: false,
            sideEffectLevel: "external-read",
            status: "failure",
            durationMs: 0,
            details: { error: err.message },
          });
          return {
            isError: true,
            content: [
              {
                type: "text",
                text: JSON.stringify(
                  createToolFailure(err.message, "PREPARE_ERROR", {
                    requestId: reqId,
                    toolName,
                    toolVersion,
                    durationMs: 0,
                  }),
                  null,
                  2,
                ),
              },
            ],
          };
        }
      },
    );

    // Tool: confirm_application_submission
    this.server.tool(
      "confirm_application_submission",
      automationServerCapabilities.find(
        (c) => c.name === "confirm_application_submission",
      )?.description || "",
      {
        approvalToken: z
          .string()
          .describe("The validation token generated by prepare_application"),
        jobUrl: z.string().url().describe("The target job posting vacancy URL"),
        dryRun: z.boolean().optional().default(false),
        approverIdentity: z
          .string()
          .optional()
          .describe(
            "The identity of the user approving this action (for audit)",
          ),
        _agentId: z.string().optional().describe("Agent Identity"),
      },
      async ({ approvalToken, jobUrl, dryRun, approverIdentity, _agentId }) => {
        const reqId = crypto.randomUUID();
        const toolName = "confirm_application_submission";
        const toolVersion = "0.1.0";
        mcpToolCallsCounter.add(1);

        try {
          const { data, durationMs } = await this.gateway.execute(
            {
              requestId: reqId,
              toolName,
              sideEffect: "submit",
              agentId: _agentId,
              payload: { approvalToken, jobUrl, dryRun, approverIdentity },
            },
            async () => {
              return await withToolTracing(
                toolName,
                toolVersion,
                reqId,
                async () => {
                  // Re-fetch context to rebuild the exact payload that was hashed
                  const context = await this.docService.getCareerContext();
                  const pref = context.preferences[0];
                  const roles = pref?.frontmatter["roles"] || [];
                  const preparedFields = {
                    rolesApplied: Array.isArray(roles)
                      ? roles.join(", ")
                      : "Software Engineer",
                    status: "Draft",
                  };

                  const expectedPayload = { jobUrl, context, preparedFields };
                  const expectedPayloadHash = crypto.createHash("sha256").update(JSON.stringify(expectedPayload)).digest("hex");

                  const isValid = await approvalStore.validateAndConsume(
                    approvalToken,
                    "confirm_application_submission",
                    expectedPayloadHash,
                    approverIdentity,
                  );

                  if (!isValid) {
                    throw new Error(
                      `Execution Blocked: Invalid, expired, or tampered approval token: ${approvalToken}`,
                    );
                  }

                  const mode =
                    process.env["AUTOMATION_RUNTIME_MODE"] || "sandbox";
                  if (mode !== "explicit-authorized-live" && !dryRun) {
                    throw new Error(
                      `Execution Blocked: AUTOMATION_RUNTIME_MODE is set to '${mode}'. Live application submissions are disabled unless mode is 'explicit-authorized-live' or dryRun is true.`,
                    );
                  }

                  // Trigger Playwright browser automation
                  const result = await this.orchestrator.orchestrate(
                    jobUrl,
                    context,
                    {
                      headless: true,
                      dryRun,
                    },
                  );

                  if (!result.success) {
                    throw new Error(
                      `Automation execution failed: ${result.errors?.join("\n")}`,
                    );
                  }

                  const appDoc = OKFDocumentFactory.createApplication(
                    result.company,
                    result.jobTitle,
                    jobUrl,
                    {
                      platform: result.platform,
                      applicationStatus: dryRun
                        ? ApplicationStatus.Saved
                        : ApplicationStatus.Applied,
                      appliedAt: result.submittedAt,
                    },
                  );

                  await this.docService.createDocument(appDoc);
                  automationSubmissionSuccessCounter.add(1);

                  return { appDoc, dryRun };
                },
              );
            },
          );

          auditLogger.log({
            requestId: approvalToken,
            toolName: "confirm_application_submission",
            autonomyLevel: "act-with-approval",
            approvalRequired: true,
            sideEffectLevel: "external-submit",
            status: "success",
            durationMs,
          });

          return {
            content: [
              {
                type: "text",
                text: JSON.stringify(
                  createToolSuccess(
                    {
                      message: data.dryRun
                        ? "Dry-run application completed successfully."
                        : "Job application successfully submitted and registered in OKF bundle.",
                      conceptId: data.appDoc.conceptId,
                    },
                    { requestId: reqId, toolName, toolVersion, durationMs },
                  ),
                  null,
                  2,
                ),
              },
            ],
          };
        } catch (err: any) {
          mcpToolFailuresCounter.add(1);

          let failReason = "automation_failed";
          if (err.message.includes("Invalid, expired, or tampered"))
            failReason = "token_validation_failed";
          if (err.message.includes("AUTOMATION_RUNTIME_MODE"))
            failReason = "runtime_mode_blocked";
          if (err.name === "MCPGatewayError") failReason = "gateway_blocked";

          auditLogger.log({
            requestId: approvalToken,
            toolName: "confirm_application_submission",
            autonomyLevel: "act-with-approval",
            approvalRequired: true,
            sideEffectLevel: "external-submit",
            status: failReason === "automation_failed" ? "failure" : "blocked",
            durationMs: 0,
            details: { reason: failReason, error: err.message },
          });

          return {
            isError: true,
            content: [
              {
                type: "text",
                text: JSON.stringify(
                  createToolFailure(err.message, failReason.toUpperCase(), {
                    requestId: reqId,
                    toolName,
                    toolVersion,
                    durationMs: 0,
                  }),
                  null,
                  2,
                ),
              },
            ],
          };
        }
      },
    );

    // Tool: capture_job_posting
    this.server.tool(
      "capture_job_posting",
      automationServerCapabilities.find((c) => c.name === "capture_job_posting")
        ?.description || "",
      { jobUrl: z.string().url(), _agentId: z.string().optional() },
      async () => {
        const reqId = crypto.randomUUID();
        const toolName = "capture_job_posting";
        const toolVersion = "0.1.0";
        mcpToolCallsCounter.add(1);

        return {
          isError: true,
          content: [
            {
              type: "text",
              text: JSON.stringify(
                createToolFailure(
                  "NOT_IMPLEMENTED: Feature deferred.",
                  "NOT_IMPLEMENTED",
                  { requestId: reqId, toolName, toolVersion, durationMs: 0 },
                ),
                null,
                2,
              ),
            },
          ],
        };
      },
    );

    // Tool: extract_platform_metadata
    this.server.tool(
      "extract_platform_metadata",
      automationServerCapabilities.find(
        (c) => c.name === "extract_platform_metadata",
      )?.description || "",
      { jobUrl: z.string().url(), _agentId: z.string().optional() },
      async () => {
        const reqId = crypto.randomUUID();
        const toolName = "extract_platform_metadata";
        const toolVersion = "0.1.0";
        mcpToolCallsCounter.add(1);

        return {
          isError: true,
          content: [
            {
              type: "text",
              text: JSON.stringify(
                createToolFailure(
                  "NOT_IMPLEMENTED: Feature deferred.",
                  "NOT_IMPLEMENTED",
                  { requestId: reqId, toolName, toolVersion, durationMs: 0 },
                ),
