      { _agentId: z.string().optional() },
      async ({ _agentId }) => {
        const reqId = crypto.randomUUID();
        const toolName = "list_pending_approvals";
        const toolVersion = "0.1.0";
        mcpToolCallsCounter.add(1);
        try {
          const { data, durationMs } = await this.gateway.execute(
            {
              requestId: reqId,
              toolName,
              sideEffect: "read",
              agentId: _agentId,
              payload: {},
            },
            async () => {
              return await withToolTracing(
                toolName,
                toolVersion,
                reqId,
                async () => {
                  return await approvalStore.getPendingApprovals();
                },
              );
            },
          );

          return {
            content: [
              {
                type: "text",
                text: JSON.stringify(
                  createToolSuccess(
                    {
                      pending: data,
                    },
                    { requestId: reqId, toolName, toolVersion, durationMs },
                  ),
                  null,
                  2,
                ),
              },
            ],
          };
        } catch (err: any) {
          mcpToolFailuresCounter.add(1);
          return {
            isError: true,
            content: [
              {
                type: "text",
                text: JSON.stringify(
                  createToolFailure(err.message, "LIST_ERROR", {
                    requestId: reqId,
                    toolName,
                    toolVersion,
                    durationMs: 0,
                  }),
                  null,
                  2,
                ),
              },
            ],
          };
        }
      },
    );

    // Tool: revoke_approval
    this.server.tool(
      "revoke_approval",
      automationServerCapabilities.find((c) => c.name === "revoke_approval")
        ?.description || "",
      {
        approvalToken: z.string().describe("The token to revoke"),
        approverIdentity: z
          .string()
          .optional()
          .describe("The identity of the user revoking this action"),
        _agentId: z.string().optional(),
      },
      async ({ approvalToken, approverIdentity, _agentId }) => {
        const reqId = crypto.randomUUID();
        const toolName = "revoke_approval";
        const toolVersion = "0.1.0";
        mcpToolCallsCounter.add(1);

        try {
          const { data, durationMs } = await this.gateway.execute(
            {
              requestId: reqId,
              toolName,
              sideEffect: "write",
              agentId: _agentId,
              payload: { approvalToken, approverIdentity },
            },
            async () => {
              return await withToolTracing(
                toolName,
                toolVersion,
                reqId,
                async () => {
                  const success = await approvalStore.revokeToken(
                    approvalToken,
                    approverIdentity,
                  );
                  if (!success) {
                    throw new Error(
                      "Token not found, already consumed, or expired",
                    );
                  }
                  return { revoked: true };
                },
              );
            },
          );

          return {
            content: [
              {
                type: "text",
                text: JSON.stringify(
                  createToolSuccess(data, {
                    requestId: reqId,
                    toolName,
                    toolVersion,
                    durationMs,
                  }),
                  null,
                  2,
                ),
              },
            ],
          };
        } catch (err: any) {
          mcpToolFailuresCounter.add(1);
          return {
            isError: true,
            content: [
              {
                type: "text",
                text: JSON.stringify(
                  createToolFailure(err.message, "REVOKE_ERROR", {
                    requestId: reqId,
                    toolName,
                    toolVersion,
                    durationMs: 0,
                  }),
                  null,
                  2,
                ),
              },
            ],
          };
        }
      },
    );

    // Tool: approve_pending_token (Generic HITL)
    this.server.tool(
      "approve_pending_token",
      "Approves a pending token in the Human-In-The-Loop gateway. Usually called by a UI.",
      {
        approvalToken: z.string().describe("The token to approve"),
        approverIdentity: z
          .string()
          .optional()
          .describe("The identity of the user approving this action"),
        _agentId: z.string().optional(),
      },
      async ({ approvalToken, approverIdentity, _agentId }) => {
        const reqId = crypto.randomUUID();
        const toolName = "approve_pending_token";
        const toolVersion = "0.1.0";
        mcpToolCallsCounter.add(1);

        try {
          const { data, durationMs } = await this.gateway.execute(
            {
              requestId: reqId,
              toolName,
              sideEffect: "write",
              agentId: _agentId,
              payload: { approvalToken, approverIdentity },
            },
            async () => {
              return await withToolTracing(
                toolName,
                toolVersion,
                reqId,
                async () => {
                  const success = await approvalStore.approveToken(
                    approvalToken,
                    approverIdentity,
                  );
                  if (!success) {
                    throw new Error("Token not found or not in PENDING state.");
                  }
                  return { approved: true };
                },
              );
            },
          );

          return {
            content: [
              {
                type: "text",
                text: JSON.stringify(
                  createToolSuccess(data, {
                    requestId: reqId,
                    toolName,
                    toolVersion,
                    durationMs,
                  }),
                  null,
                  2,
                ),
              },
            ],
          };
        } catch (err: any) {
          mcpToolFailuresCounter.add(1);
          return {
            isError: true,
            content: [
              {
                type: "text",
                text: JSON.stringify(
                  createToolFailure(err.message, "APPROVE_ERROR", {
                    requestId: reqId,
                    toolName,
                    toolVersion,
                    durationMs: 0,
                  }),
                  null,
                  2,
                ),
              },
            ],
          };
        }
      },
    );

    // Tool: list_audit_logs
    this.server.tool(
      "list_audit_logs",
      automationServerCapabilities.find((c) => c.name === "list_audit_logs")
        ?.description || "",
      {
        limit: z
          .number()
          .optional()
          .default(100)
          .describe("Max number of logs to return"),
        _agentId: z.string().optional(),
      },
      async ({ limit, _agentId }) => {
        const reqId = crypto.randomUUID();
        const toolName = "list_audit_logs";
        const toolVersion = "0.1.0";
        mcpToolCallsCounter.add(1);

        try {
          const { data, durationMs } = await this.gateway.execute(
            {
              requestId: reqId,
              toolName,
              sideEffect: "read",
              agentId: _agentId,
              payload: { limit },
            },
            async () => {
              return await withToolTracing(
                toolName,
                toolVersion,
                reqId,
                async () => {
                  return await approvalStore.getAuditLogs(limit);
                },
              );
            },
          );

          return {
            content: [
              {
                type: "text",
                text: JSON.stringify(
                  createToolSuccess(
                    {
                      logs: data,
                    },
                    { requestId: reqId, toolName, toolVersion, durationMs },
                  ),
                  null,
                  2,
                ),
              },
            ],
          };
        } catch (err: any) {
          mcpToolFailuresCounter.add(1);
          return {
            isError: true,
            content: [
              {
                type: "text",
                text: JSON.stringify(
                  createToolFailure(err.message, "LIST_AUDIT_ERROR", {
                    requestId: reqId,
                    toolName,
                    toolVersion,
                    durationMs: 0,
                  }),
                  null,
                  2,
                ),
              },
            ],
          };
        }
      },
    );

    // =====================================
    // Customer Support Capabilities
    // =====================================
    this.server.tool(
      "request_support_action_approval",
      automationServerCapabilities.find((c) => c.name === "request_support_action_approval")?.description || "",
      {
        ticketId: z.string().describe("Support ticket ID"),
        actionType: z.string().describe("Type of action (e.g. refund, password_reset)"),
        reason: z.string().describe("Reason for action"),
        _agentId: z.string().optional(),
      },
      async ({ ticketId, actionType, reason, _agentId }) => {
        mcpToolCallsCounter.add(1);

        try {
          const payload = { ticketId, actionType, reason };
          const metadata = { platform: "support-crm" };
          const payloadHash = crypto.createHash("sha256").update(JSON.stringify(payload)).digest("hex");
          const token = await approvalStore.generateToken(
            crypto.randomUUID(),
            "record_support_resolution",
            payloadHash,
            "high",
            "write",
            _agentId || "anonymous",
            metadata
          );

          return {
            content: [
              {
                type: "text",
                text: JSON.stringify({ ok: true, approvalToken: token, message: "Action staged for approval." }, null, 2),
              },
            ],
          };
        } catch (err: any) {
          mcpToolFailuresCounter.add(1);
          return { isError: true, content: [{ type: "text", text: err.message }] };
        }
      }
    );

    this.server.tool(
      "record_support_resolution",
      automationServerCapabilities.find((c) => c.name === "record_support_resolution")?.description || "",
      {
        approvalToken: z.string().describe("The approval token"),
        ticketId: z.string().describe("Support ticket ID"),
        actionType: z.string().describe("Type of action (e.g. refund, password_reset)"),
        reason: z.string().describe("Reason for action"),
        approverIdentity: z.string().optional(),
        _agentId: z.string().optional(),
      },
      async ({ approvalToken, ticketId, actionType, reason, approverIdentity }) => {
        const toolName = "record_support_resolution";
        mcpToolCallsCounter.add(1);

        try {
          const expectedPayload = { ticketId, actionType, reason };
          const expectedPayloadHash = crypto.createHash("sha256").update(JSON.stringify(expectedPayload)).digest("hex");
          const isValid = await approvalStore.validateAndConsume(approvalToken, toolName, expectedPayloadHash, approverIdentity);
          if (!isValid) throw new Error("Execution Blocked: Invalid, expired, or tampered approval token.");

          auditLogger.log({
            requestId: approvalToken,
            toolName,
            autonomyLevel: "act-with-approval",
            approvalRequired: true,
            sideEffectLevel: "external-submit",
            status: "success",
            durationMs: 100,
          });

          return {
            content: [
              {
                type: "text",
                text: JSON.stringify({ ok: true, message: `Support action ${actionType} for ticket ${ticketId} resolved.` }, null, 2),
              },
            ],
          };
        } catch (err: any) {
          mcpToolFailuresCounter.add(1);
          return { isError: true, content: [{ type: "text", text: err.message }] };
        }
      }
    );

    // Generic stub for read-only support tools
    const readOnlySupportTools = [
      "classify_support_intent",
      "retrieve_support_context",
      "draft_support_reply",
      "validate_support_reply",
      "redact_support_pii",
      "preview_support_action",
      "detect_support_knowledge_gap"
    ];

    for (const st of readOnlySupportTools) {
      this.server.tool(
        st,
        automationServerCapabilities.find((c) => c.name === st)?.description || "",
        { _agentId: z.string().optional() },
        async () => {
          mcpToolCallsCounter.add(1);
          return {
            content: [{ type: "text", text: JSON.stringify({ ok: true, message: `Mock result for ${st}` }, null, 2) }]
          };
        }
      );
    }

  }

  private detectPlatform(url: string): string {
    const lower = url.toLowerCase();
    if (lower.includes("linkedin")) return "LinkedIn";
    if (lower.includes("gupy")) return "Gupy";
    if (lower.includes("indeed")) return "Indeed";
    return "GenericPlatform";
  }
}

/**
 * @module http-server
 * @description Entrypoint for the dynamic MCP Profile Server over HTTP/SSE with Bearer Auth.
 */

import express from "express";
import cors from "cors";
import path from "node:path";
import fs from "node:fs";
import { SSEServerTransport } from "@modelcontextprotocol/sdk/server/sse.js";
import { startTelemetry, type AgentKnowledgeIR } from "@akcp/core";
import { AKCPProfileServer } from "./server.js";

async function main() {
  try {
    startTelemetry();

    const contextPackEnv = process.env["AKCP_CONTEXT_PACK_PATH"];
    if (!contextPackEnv) {
      throw new Error("[AKCP Profile Server] AKCP_CONTEXT_PACK_PATH environment variable is required.");
    }

    const contextPackPath = path.resolve(contextPackEnv);
    if (!fs.existsSync(contextPackPath)) {
      throw new Error(`[AKCP Profile Server] Context pack not found at ${contextPackPath}`);
    }

    const irContent = fs.readFileSync(contextPackPath, "utf-8");
    const ir: AgentKnowledgeIR = JSON.parse(irContent);

    const app = express();
    app.use(cors());

    // Basic Auth Middleware
    const expectedToken = process.env["AKCP_AUTH_TOKEN"];
    app.use((req, res, next) => {
      if (!expectedToken) {
        // If no token is configured, allow (or you could reject, but for MVP we allow if not set)
        return next();
      }
      const authHeader = req.headers.authorization;
      if (!authHeader || !authHeader.startsWith("Bearer ")) {
        return res.status(401).json({ error: "Unauthorized: Missing or invalid Bearer token" });
      }
      const token = authHeader.split(" ")[1];
      if (token !== expectedToken) {
        return res.status(401).json({ error: "Unauthorized: Invalid token" });
      }
      next();
    });

    let transport: SSEServerTransport | null = null;

    app.get("/mcp/sse", async (_req, res) => {
      console.log("[AKCP Profile Server] New SSE connection established");
      transport = new SSEServerTransport("/mcp/messages", res);

      const agentIdentity = expectedToken ? "authenticated-agent" : "anonymous-agent";

      const mcpProfileServer = new AKCPProfileServer(ir, { policies: ir.policies || {} }, agentIdentity);
      await mcpProfileServer.getServerInstance().connect(transport);
    });

    app.post("/mcp/messages", express.json(), async (req, res) => {
      if (!transport) {
        res.status(400).json({ error: "SSE connection not established" });
        return;
      }
      await transport.handlePostMessage(req, res);
    });

    const PORT = process.env.PORT || 3001;
    app.listen(PORT, () => {
      console.log(`[AKCP Profile Server] HTTP/SSE Server listening on port ${PORT}`);
      if (expectedToken) {
        console.log(`[AKCP Profile Server] Auth enabled. Requires Bearer token.`);
      } else {
        console.warn(`[AKCP Profile Server] WARNING: No AKCP_AUTH_TOKEN set. Running without authentication.`);
      }
    });

  } catch (error) {
    console.error("[AKCP Profile Server] Fatal startup error:", error);
    process.exit(1);
  }
}

main().catch((err) => {
  console.error("[AKCP Profile Server] Unhandled rejection:", err);
  process.exit(1);
});

#!/usr/bin/env node

import express from "express";
import cors from "cors";
import fs from "node:fs";
import path from "node:path";
import { SSEServerTransport } from "@modelcontextprotocol/sdk/server/sse.js";
import { AKCPProfileServer } from "./server.js";



// Read the previously compiled AgentKnowledgeIR
const irPath = path.resolve(process.cwd(), "dist/knowledge-ir.json");
if (!fs.existsSync(irPath)) {
  console.error(`[AKCP Profile Server - SSE] Missing compiled IR at ${irPath}.`);
  console.error(`Run 'akcp compile' first to generate the knowledge graph.`);
  process.exit(1);
}

const irStr = fs.readFileSync(irPath, "utf-8");
const ir = JSON.parse(irStr);

// Instantiate the AKCP Profile Server logic
const profileServer = new AKCPProfileServer(ir, { policies: ir.policies || {} }, "mcp-sse-client");
const mcp = profileServer.getServerInstance();

const app = express();
app.use(cors());

// Mock JWT Auth Middleware from Phase 5 (Enterprise Gateway Security)
const requireAuth = (req: express.Request, res: express.Response, next: express.NextFunction) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith("Bearer ")) {
    res.status(401).json({ error: "Missing or invalid Authorization Bearer token" });
    return;
  }

  const token = authHeader.substring(7);
  // For MVP: Accept admin@corp.com directly as the token payload.
  // In production, this would verify a real JWT signature against an IdP (e.g., Auth0).
  if (token !== "admin@corp.com" && !token.includes("@")) {
    res.status(403).json({ error: "Unauthorized Identity" });
    return;
  }

  // We consider them authenticated
  (req as any).user = { identity: token };
  next();
};

let globalTransport: SSEServerTransport | null = null;

// SSE connection endpoint
app.get("/sse", requireAuth, async (req, res) => {
  console.log(`[SSE] New connection from ${req.ip} (User: ${(req as any).user.identity})`);
  globalTransport = new SSEServerTransport("/message", res);

  await mcp.connect(globalTransport);

  req.on('close', () => {
    console.log(`[SSE] Connection closed for ${req.ip}`);
    globalTransport = null;
  });
});

// Message endpoint to receive JSON-RPC messages from the client
app.post("/message", requireAuth, express.json(), async (req, res) => {
  if (!globalTransport) {
    res.status(500).json({ error: "No active SSE connection found." });
    return;
  }
  try {
    await globalTransport.handlePostMessage(req, res);
  } catch (err: any) {
    console.error("[SSE] Error handling message:", err);
    res.status(500).json({ error: "Internal Server Error" });
  }
});

const PORT = process.env.PORT ? parseInt(process.env.PORT, 10) : 4000;

app.listen(PORT, () => {
  console.log(`[AKCP Profile Server - SSE] Listening on port ${PORT}`);
  console.log(`[AKCP Profile Server - SSE] Endpoint: http://localhost:${PORT}/sse`);
  console.log(`[AKCP Profile Server - SSE] Identity Authorization Required (Bearer Token)`);
});

/**
 * @module server
 * @description Configures tools, resources, and prompts dynamically for the MCP Profile Server.
 */

import {
  McpServer,
} from "@modelcontextprotocol/sdk/server/mcp.js";
import { z } from "zod";
import crypto from "node:crypto";
import {
  mcpToolCallsCounter,
  mcpToolFailuresCounter,
  createToolSuccess,
  createToolFailure,
  withToolTracing,
  MCPGateway,
  type GatewayConfig,
  type AgentKnowledgeIR,
  LakeraGateway,
  type ISecurityGateway
} from "@akcp/core";

export class AKCPProfileServer {
  private readonly server: McpServer;
  private readonly gateway: MCPGateway;
  private readonly ir: AgentKnowledgeIR;
  private readonly agentIdentity: string;
  private readonly securityGateway: ISecurityGateway;

  constructor(
    ir: AgentKnowledgeIR,
    gatewayConfig: GatewayConfig = { policies: {} },
    agentIdentity: string = "mcp-client"
  ) {
    this.ir = ir;
    this.gateway = new MCPGateway(gatewayConfig);
    this.agentIdentity = agentIdentity;
    this.securityGateway = new LakeraGateway();

    // Create the MCP server instance
    this.server = new McpServer({
      name: "akcp-profile-server",
      version: "1.0.0",
    });

    this.registerResources();
    this.registerTools();
  }

  getServerInstance(): McpServer {
    return this.server;
  }

  /**
   * Register resources dynamically based on the AgentKnowledgeIR concepts.
   */
  private registerResources(): void {
    if (!this.ir.concepts || this.ir.concepts.length === 0) {
      console.warn("[AKCP Profile Server] No concepts found in IR to register as resources.");
      return;
    }

    for (const concept of this.ir.concepts) {
      if (concept.conceptId.includes("..")) {
        console.warn(`[SECURITY] Skipping resource with invalid path traversal in ID: ${concept.conceptId}`);
        continue;
      }

      const uri = `knowledge://${this.ir.bundleId}/${concept.conceptId}`;
      const name = concept.conceptId.replace(/\//g, "-");

      this.server.resource(
        name,
        uri,
        {
          mimeType: "text/markdown",
          description: `Knowledge asset: ${concept.conceptId} (Type: ${concept.type})`,
        },
        async () => {
          const summaryStr = concept.frontmatter.summary ? `\n> Summary: ${concept.frontmatter.summary}\n` : "";
          return {
            contents: [
              {
                uri,
                mimeType: "text/markdown",
                text: `---\n${JSON.stringify(concept.frontmatter, null, 2)}\n---${summaryStr}\n\n${concept.body}`,
              },
            ],
          };
        }
      );
    }
  }

  /**
   * Register tools dynamically based on capabilities defined in the IR.
   */
  private registerTools(): void {
    const capabilities = this.ir.capabilities || [];

    // Filter out only tools
    const tools = capabilities.filter((cap: any) => cap.kind === "tool" || cap.kind === "mcp-tool" || cap.type === "tool" || cap.type === "mcp-tool");

    if (tools.length === 0) {
      console.warn("[AKCP Profile Server] No tool capabilities found in IR.");
    }

    // Add read_document_chunk tool for Context Pagination
    this.server.tool(
      "read_document_chunk",
      "Read a paginated chunk of a specific knowledge concept to avoid context window collapse.",
      {
        conceptId: z.string().describe("The conceptId of the document to read"),
        offset: z.number().default(0).describe("Character offset to start reading from"),
        limit: z.number().default(4000).describe("Maximum number of characters to read (chunk size)"),
        summaryOnly: z.boolean().optional().describe("If true, only returns the summary of the document, if available."),
      },
      async ({ conceptId, offset, limit, summaryOnly }) => {
        mcpToolCallsCounter.add(1);
        const concept = this.ir.concepts?.find((c) => c.conceptId === conceptId);

        if (!concept) {
          mcpToolFailuresCounter.add(1);
          return {
            isError: true,
            content: [{ type: "text", text: `Error: Concept ${conceptId} not found.` }],
          };
        }

        let fullText = "";

        if (summaryOnly && concept.frontmatter.summary) {
          fullText = `---\n${JSON.stringify(concept.frontmatter, null, 2)}\n---\n\n> Summary: ${concept.frontmatter.summary}`;
        } else {
          fullText = `---\n${JSON.stringify(concept.frontmatter, null, 2)}\n---\n\n${concept.body}`;
        }

        const chunk = fullText.slice(offset, offset + limit);
        const hasMore = offset + limit < fullText.length;

        return {
          content: [
            {
              type: "text",
              text: JSON.stringify({
                conceptId,
                offset,
                limit,
                totalLength: fullText.length,
                hasMore,
                chunk,
              }, null, 2),
            },
          ],
        };
      }
    );

    for (const cap of tools) {
      if (cap.name) {
        const rawCap = cap as any;
        const schema = cap.inputsSchema || rawCap.inputSchema || rawCap.parameters || {};

        // Convert basic JSON schema to Zod schema dynamically
        const zodShape: Record<string, z.ZodTypeAny> = {};

        if (schema.properties) {
          for (const [key, prop] of Object.entries<any>(schema.properties)) {
            let zType: z.ZodTypeAny = z.any();
            if (prop.type === "string") zType = z.string();
            else if (prop.type === "number") zType = z.number();
            else if (prop.type === "boolean") zType = z.boolean();

            if (prop.description) zType = zType.describe(prop.description);

            if (!schema.required || !schema.required.includes(key)) {
              zType = zType.optional();
            }
            zodShape[key] = zType;
          }
        }

        this.server.tool(
          cap.name,
          cap.description || `Tool: ${cap.name}`,
          zodShape,
          async (args) => {
            const reqId = crypto.randomUUID();
            mcpToolCallsCounter.add(1);

            // Gating based on requiresApproval and sideEffects could happen here
            if (cap.requiresApproval) {
              console.warn(`[SECURITY] Tool ${cap.name} requires human approval! (Simulated)`);
            }

            // WAF Security Check
            const wafResult = await this.securityGateway.checkPrompt(JSON.stringify(args));
            if (wafResult.flagged) {
              mcpToolFailuresCounter.add(1);
              return {
                isError: true,
                content: [
                  {
                    type: "text",
                    text: JSON.stringify(
                      createToolFailure(`Security Gateway Blocked Execution: ${wafResult.reason}`, "SECURITY_BLOCK", {
                        requestId: reqId,
                        toolName: cap.name,
                        toolVersion: "1.0.0",
                        durationMs: 0,
                      }),
                      null,
                      2
                    )
                  }
                ]
              };
            }

            try {
              let mappedSideEffect: "read" | "write" | "submit" = "read";
              if (cap.sideEffects?.includes("write")) mappedSideEffect = "write";
              if (cap.sideEffects === "external-submit") mappedSideEffect = "submit";

              const { data, durationMs } = await this.gateway.execute(
                {
                  requestId: reqId,
                  toolName: cap.name,
                  sideEffect: mappedSideEffect,
                  agentId: this.agentIdentity,
                  payload: args,
                },
                async () => {
                  return await withToolTracing(
                    cap.name,
                    "1.0.0",
                    reqId,
                    async () => {
                      return {
                        status: "simulated_success",
                        message: `Tool ${cap.name} executed successfully with args`,
                        args
                      };
                    },
                  );
                },
              );

              return {
                content: [
                  {
                    type: "text",
                    text: JSON.stringify(
                      createToolSuccess(data, {
                        requestId: reqId,
                        toolName: cap.name,
                        toolVersion: "1.0.0",
                        durationMs,
                        riskLevel: cap.riskLevel || "low"
                      }),
                      null,
                      2,
                    ),
                  },
                ],
              };
            } catch (err: any) {
              mcpToolFailuresCounter.add(1);
              return {
                isError: true,
                content: [
                  {
                    type: "text",
                    text: JSON.stringify(
                      createToolFailure(err.message, "INTERNAL_ERROR", {
                        requestId: reqId,
                        toolName: cap.name,
                        toolVersion: "1.0.0",
                        durationMs: 0,
                      }),
                      null,
                      2,
                    ),
                  },
                ],
              };
            }
          }
        );
      }
    }
  }
}

